const assert = require("node:assert/strict");
const crypto = require("node:crypto");
const fs = require("node:fs");
const http = require("node:http");
const os = require("node:os");
const path = require("node:path");
const test = require("node:test");
const { buildApp } = require("../server/app");
const { DEFAULT_EMAIL, DEFAULT_PASSWORD } = require("../server/db");

async function withApp(fn) {
  const app = buildApp({ dbPath: ":memory:" });
  await app.ready();
  try {
    await fn(app);
  } finally {
    await app.close();
  }
}

async function login(app, email = DEFAULT_EMAIL, password = DEFAULT_PASSWORD) {
  const response = await app.inject({
    method: "POST",
    url: "/api/login",
    payload: { email, password }
  });
  assert.equal(response.statusCode, 200, response.body);
  return response.headers["set-cookie"];
}

let publicQuoteAcceptCounter = 1;
function nextPublicQuoteAcceptRemoteAddress() {
  const n = publicQuoteAcceptCounter++;
  return `198.51.${100 + Math.floor(n / 200)}.${(n % 200) + 1}`;
}

function totpCode(secretBase32, nowMs = Date.now()) {
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
  const clean = String(secretBase32 || "").replace(/=+$/g, "").replace(/\s+/g, "").toUpperCase();
  let bits = "";
  for (const char of clean) {
    const value = alphabet.indexOf(char);
    if (value < 0) continue;
    bits += value.toString(2).padStart(5, "0");
  }
  const bytes = [];
  for (let index = 0; index + 8 <= bits.length; index += 8) {
    bytes.push(parseInt(bits.slice(index, index + 8), 2));
  }
  const counter = Math.floor(nowMs / 30000);
  const counterBuffer = Buffer.alloc(8);
  counterBuffer.writeBigUInt64BE(BigInt(counter));
  const digest = crypto.createHmac("sha1", Buffer.from(bytes)).update(counterBuffer).digest();
  const offset = digest[digest.length - 1] & 0x0f;
  const binary = ((digest[offset] & 0x7f) << 24)
    | ((digest[offset + 1] & 0xff) << 16)
    | ((digest[offset + 2] & 0xff) << 8)
    | (digest[offset + 3] & 0xff);
  return String(binary % 1000000).padStart(6, "0");
}

test("health exposes the Armosphera One suite modules", async () => {
  await withApp(async app => {
    const response = await app.inject({ method: "GET", url: "/api/health" });
    assert.equal(response.statusCode, 200);
    const body = response.json();
    assert.equal(body.ok, true);
    assert.equal(body.product, "Armosphera One");
    assert.ok(body.modules.includes("crm"));
    assert.ok(body.modules.includes("finance"));
    assert.ok(body.modules.includes("analytics"));
  });
});

test("owner login loads organization, app launcher, localization, and audit", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const response = await app.inject({ method: "GET", url: "/api/suite", headers: { cookie } });
    assert.equal(response.statusCode, 200, response.body);
    const body = response.json();
    assert.equal(body.organization.currency, "AMD");
    assert.equal(body.organization.locale, "hy-AM");
    assert.equal(body.apps.length, 10);
    assert.ok(body.apps.some(app => app.id === "finance"));
    assert.ok(body.apps.some(app => app.id === "copilot"));
    assert.ok(body.localization.some(item => item.key === "vat-20" && item.status === "review"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.equal(audit.statusCode, 200);
    assert.ok(audit.json().events.some(event => event.type === "auth.login"));
  });
});

test("existing suite databases receive the copilot launcher app on reopen", async () => {
  const root = fs.mkdtempSync(path.join(os.tmpdir(), "a1-suite-app-layer-"));
  const dbPath = path.join(root, "suite.sqlite");
  const first = buildApp({ dbPath });
  await first.ready();
  try {
    const removed = first.db.prepare("DELETE FROM apps WHERE id = ?").run("copilot");
    assert.equal(removed.changes, 1);
  } finally {
    await first.close();
  }

  const second = buildApp({ dbPath });
  await second.ready();
  try {
    const row = second.db.prepare("SELECT id, priority FROM apps WHERE id = ?").get("copilot");
    assert.equal(row.id, "copilot");
    assert.equal(row.priority, 3);
    const assignment = second.db.prepare(`
      SELECT enabled FROM app_assignments
      WHERE role = ? AND app_id = ?
    `).get("Accountant", "copilot");
    assert.equal(assignment.enabled, 1);

    const cookie = await login(second);
    const suite = await second.inject({ method: "GET", url: "/api/suite", headers: { cookie } });
    assert.equal(suite.statusCode, 200, suite.body);
    const appIds = suite.json().apps.map(app => app.id);
    assert.equal(appIds[2], "copilot");
  } finally {
    await second.close();
    fs.rmSync(root, { recursive: true, force: true });
  }
});

test("global audit feed is limited to audit reader roles", async () => {
  await withApp(async app => {
    const unauthenticated = await app.inject({ method: "GET", url: "/api/audit" });
    assert.equal(unauthenticated.statusCode, 401);

    const supportCookie = await login(app, "support@armosphera.local");
    const supportAudit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: supportCookie } });
    assert.equal(supportAudit.statusCode, 403);

    const accountantCookie = await login(app, "accountant@armosphera.local");
    const accountantAudit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: accountantCookie } });
    assert.equal(accountantAudit.statusCode, 403);

    const serviceManagerCookie = await login(app, "service.manager@armosphera.local");
    const serviceManagerAudit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: serviceManagerCookie } });
    assert.equal(serviceManagerAudit.statusCode, 403);

    const orgId = app.db.prepare("SELECT org_id AS orgId FROM users WHERE email = ?").get(DEFAULT_EMAIL).orgId;
    const ownerPasswordHash = app.db.prepare("SELECT password_hash AS hash FROM users WHERE email = ?").get(DEFAULT_EMAIL).hash;
    app.db.prepare("INSERT INTO users (id, org_id, email, name, role, password_hash, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)")
      .run("user-admin-audit-reader", orgId, "admin-audit@armosphera.local", "Admin Audit Reader", "Admin", ownerPasswordHash, new Date().toISOString());
    const adminCookie = await login(app, "admin-audit@armosphera.local");
    const adminAudit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: adminCookie } });
    assert.equal(adminAudit.statusCode, 200, adminAudit.body);
    assert.ok(adminAudit.json().events.some(event => event.type === "auth.login"));

    const ownerCookie = await login(app);
    const ownerAudit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.equal(ownerAudit.statusCode, 200, ownerAudit.body);
    assert.ok(ownerAudit.json().events.some(event => event.type === "auth.login"));

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorAudit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: auditorCookie } });
    assert.equal(auditorAudit.statusCode, 200, auditorAudit.body);
    assert.ok(auditorAudit.json().events.some(event => event.type === "auth.login"));
  });
});

