test("app assignment rejects malformed metadata before mutation", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const countAssignments = () => app.db.prepare(`
      SELECT COUNT(*) AS count
      FROM app_assignments
      WHERE org_id = ? AND app_id = ?
    `).get("org-armosphera-demo", "flow").count;
    const countAudits = () => app.db.prepare(`
      SELECT COUNT(*) AS count
      FROM audit_events
      WHERE type = ? AND json_extract(details, '$.appId') = ?
    `).get("app.assignment.updated", "flow").count;
    const beforeAssignments = countAssignments();
    const beforeAudits = countAudits();

    const rejectedNull = await app.inject({
      method: "POST",
      url: "/api/apps/flow/assign",
      headers: { cookie, "content-type": "application/json" },
      payload: "null"
    });
    assert.equal(rejectedNull.statusCode, 400, rejectedNull.body);

    const malformedPayloads = [
      ["secret-app-assignment-array-body-token"],
      { role: { value: "Support", token: "secret-app-assignment-role-object-token" }, enabled: true },
      { role: ["Support"], enabled: true },
      { role: "Support\nsecret-app-assignment-role-control-token", enabled: true },
      { role: `${"S".repeat(81)}secret-app-assignment-role-long-token`, enabled: true },
      { role: "Support", enabled: "true" },
      { role: "Support", enabled: { value: true, token: "secret-app-assignment-enabled-object-token" } }
    ];

    for (const payload of malformedPayloads) {
      const rejected = await app.inject({
        method: "POST",
        url: "/api/apps/flow/assign",
        headers: { cookie },
        payload
      });
      assert.equal(rejected.statusCode, 400, rejected.body);
      assert.doesNotMatch(rejected.body, /secret-app-assignment-/);
      assert.equal(countAssignments(), beforeAssignments);
      assert.equal(countAudits(), beforeAudits);
    }

    const valid = await app.inject({
      method: "POST",
      url: "/api/apps/flow/assign",
      headers: { cookie },
      payload: { role: "Support", enabled: true }
    });
    assert.equal(valid.statusCode, 200, valid.body);
    assert.equal(countAssignments(), beforeAssignments + 1);
    assert.equal(countAudits(), beforeAudits + 1);
  });
});

test("app assignment rejects unknown roles before mutating access-review evidence", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    app.db.prepare(`
      INSERT INTO app_assignments (org_id, role, app_id, enabled)
      VALUES (?, ?, ?, ?)
    `).run("org-armosphera-demo", "Ghost Role", "finance", 1);

    const rejected = await app.inject({
      method: "POST",
      url: "/api/apps/finance/assign",
      headers: { cookie },
      payload: { role: "Ghost Role", enabled: true }
    });
    assert.equal(rejected.statusCode, 400, rejected.body);
    assert.match(rejected.body, /Unknown role/);

    const stored = app.db.prepare(`
      SELECT enabled
      FROM app_assignments
      WHERE org_id = ? AND role = ?
    `).get("org-armosphera-demo", "Ghost Role");
    assert.equal(stored.enabled, 1);

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.equal(audit.statusCode, 200, audit.body);
    assert.equal(audit.json().events.some(event => event.type === "app.assignment.updated" && event.details?.role === "Ghost Role"), false);

    const created = await app.inject({
      method: "POST",
      url: "/api/admin/access-reviews",
      headers: { cookie },
      payload: {
        reviewPeriod: "2026-Q2",
        note: "Access review after rejected role assignment"
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    assert.equal(created.json().review.payload.roles.some(role => role.role === "Ghost Role"), false);
    assert.equal(created.json().review.payload.appMatrix.some(app => app.roles.includes("Ghost Role")), false);
    assert.equal(created.json().review.payload.orphanedAssignmentRoles.includes("Ghost Role"), false);
    assert.deepEqual(created.json().review.payload.invalidAssignmentRoles, ["Ghost Role"]);
    assert.ok(created.json().review.payload.findings.includes("invalid-app-assignment-roles-detected"));
  });
});

test("owner can create an access review packet for auditor evidence", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const created = await app.inject({
      method: "POST",
      url: "/api/admin/access-reviews",
      headers: { cookie },
      payload: {
        reviewPeriod: "2026-Q2",
        note: "Pilot readiness access review before customer onboarding"
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const body = created.json();
    assert.equal(body.review.status, "verified");
    assert.equal(body.review.reviewPeriod, "2026-Q2");
    assert.equal(body.review.payload.kind, "armosphera-one-access-review");
    assert.equal(body.review.payload.organization.id, "org-armosphera-demo");
    assert.ok(body.review.payload.roles.some(role => role.role === "Accountant" && role.apps.includes("finance")));
    assert.ok(body.review.payload.roles.some(role => role.role === "Auditor" && role.apps.includes("analytics") && !role.apps.includes("finance")));
    assert.ok(body.review.payload.privilegedUsers.some(user => user.role === "Owner" && user.email === DEFAULT_EMAIL));
    assert.ok(body.review.payload.orphanedAssignmentRoles.includes("Admin"));
    assert.ok(body.review.payload.findings.includes("mfa-ready-admin-path-required"));
    assert.ok(body.review.payload.findings.includes("auditor-readonly-access-review-enabled"));
    assert.equal(JSON.stringify(body.review.payload).includes("password_hash"), false);
    assert.equal(sha256(JSON.stringify(body.review.payload)), body.review.checksum);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const listed = await app.inject({
      method: "GET",
      url: "/api/admin/access-reviews",
      headers: { cookie: auditorCookie }
    });
    assert.equal(listed.statusCode, 200, listed.body);
    assert.ok(listed.json().reviews.some(review => review.id === body.review.id && review.payload === undefined));

    const auditorCreate = await app.inject({
      method: "POST",
      url: "/api/admin/access-reviews",
      headers: { cookie: auditorCookie },
      payload: { reviewPeriod: "2026-Q2" }
    });
    assert.equal(auditorCreate.statusCode, 403);

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.ok(audit.json().events.some(event => event.type === "admin.access_review.created" && event.details.reviewId === body.review.id));
  });
});

test("privileged users can enable MFA and must satisfy challenge before session creation", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const supportCookie = await login(app, "support@armosphera.local");

    const supportDenied = await app.inject({
      method: "POST",
      url: "/api/security/mfa/enroll",
      headers: { cookie: supportCookie },
      payload: { label: "Support phone" }
    });
    assert.equal(supportDenied.statusCode, 403);

    const nullBodyDenied = await app.inject({
      method: "POST",
      url: "/api/security/mfa/enroll",
      headers: { cookie: ownerCookie, "content-type": "application/json" },
      payload: "null"
    });
    assert.equal(nullBodyDenied.statusCode, 400);
    assert.equal(nullBodyDenied.json().message, "MFA enrollment body must be an object");

    const objectLabelDenied = await app.inject({
      method: "POST",
      url: "/api/security/mfa/enroll",
      headers: { cookie: ownerCookie },
      payload: { label: { text: "Owner authenticator app" } }
    });
    assert.equal(objectLabelDenied.statusCode, 400);
    assert.equal(objectLabelDenied.json().message, "MFA enrollment label must be a string");

    const nullLabelDenied = await app.inject({
      method: "POST",
      url: "/api/security/mfa/enroll",
      headers: { cookie: ownerCookie },
      payload: { label: null }
    });
    assert.equal(nullLabelDenied.statusCode, 400);
    assert.equal(nullLabelDenied.json().message, "MFA enrollment label must be a string");

    const defaultLabelEnrollment = await app.inject({
      method: "POST",
      url: "/api/security/mfa/enroll",
      headers: { cookie: ownerCookie }
    });
    assert.equal(defaultLabelEnrollment.statusCode, 200, defaultLabelEnrollment.body);
    assert.equal(defaultLabelEnrollment.json().factor.label, "Authenticator app");

    const before = await app.inject({ method: "GET", url: "/api/security/mfa", headers: { cookie: ownerCookie } });
    assert.equal(before.statusCode, 200, before.body);
    assert.equal(before.json().mfaRequiredForRole, true);
    assert.equal(before.json().factors.length, 1);

    const enrolled = await app.inject({
      method: "POST",
      url: "/api/security/mfa/enroll",
      headers: { cookie: ownerCookie },
      payload: { label: "Owner authenticator app" }
    });
    assert.equal(enrolled.statusCode, 200, enrolled.body);
    const enrollment = enrolled.json();
    assert.equal(enrollment.factor.status, "pending");
    assert.equal(enrollment.factor.factorType, "totp");
    assert.match(enrollment.setup.manualSetupKey, /^[A-Z2-7]{32}$/);
    assert.ok(enrollment.setup.otpauthUrl.includes("Armosphera%20One"));

    const malformedVerifyBody = await app.inject({
      method: "POST",
      url: "/api/security/mfa/verify-enrollment",
      headers: { cookie: ownerCookie, "content-type": "application/json" },
      payload: "null"
    });
    assert.equal(malformedVerifyBody.statusCode, 400);
    assert.equal(malformedVerifyBody.json().message, "MFA verification requires safe metadata");

    const malformedVerifyFields = await app.inject({
      method: "POST",
      url: "/api/security/mfa/verify-enrollment",
      headers: { cookie: ownerCookie },
      payload: { factorId: { id: enrollment.factor.id }, code: { value: "000000" } }
    });
    assert.equal(malformedVerifyFields.statusCode, 400);
    assert.equal(malformedVerifyFields.json().message, "MFA verification requires safe metadata");

    const badVerify = await app.inject({
      method: "POST",
      url: "/api/security/mfa/verify-enrollment",
      headers: { cookie: ownerCookie },
      payload: { factorId: enrollment.factor.id, code: "000000" }
    });
    assert.equal(badVerify.statusCode, 401);

    const verified = await app.inject({
      method: "POST",
      url: "/api/security/mfa/verify-enrollment",
      headers: { cookie: ownerCookie },
      payload: { factorId: enrollment.factor.id, code: totpCode(enrollment.setup.manualSetupKey) }
    });
    assert.equal(verified.statusCode, 200, verified.body);
    assert.equal(verified.json().factor.status, "active");
    assert.equal(verified.json().mfa.enabled, true);

    const oldPasswordSession = await app.inject({
      method: "GET",
      url: "/api/admin/sessions",
      headers: { cookie: ownerCookie }
    });
    assert.equal(oldPasswordSession.statusCode, 401);

    const passwordOnly = await app.inject({
      method: "POST",
      url: "/api/login",
      payload: { email: DEFAULT_EMAIL, password: DEFAULT_PASSWORD }
    });
    assert.equal(passwordOnly.statusCode, 200, passwordOnly.body);
    assert.equal(passwordOnly.json().mfaRequired, true);
    assert.match(passwordOnly.json().challengeId, /^mfa-challenge-/);
    assert.equal(passwordOnly.headers["set-cookie"], undefined);

    const challengeStatus = () => app.db.prepare("SELECT status FROM login_mfa_challenges WHERE id = ?").get(passwordOnly.json().challengeId).status;
    const failedMfaAuditCount = () => app.db.prepare("SELECT COUNT(*) AS count FROM audit_events WHERE type = ?").get("auth.mfa.failed").count;
    const verifiedSessionCount = () => app.db.prepare("SELECT COUNT(*) AS count FROM sessions WHERE mfa_verified = 1").get().count;
    const beforeMalformedChallenge = challengeStatus();
    const beforeMalformedFailedAudits = failedMfaAuditCount();
    const beforeMalformedVerifiedSessions = verifiedSessionCount();
    const malformedMfaLoginRequests = [
      { payload: { challengeId: { id: passwordOnly.json().challengeId, token: "secret-mfa-login-challenge-object-token" }, code: "000000" } },
      { payload: { challengeId: passwordOnly.json().challengeId, code: { value: "000000", token: "secret-mfa-login-code-object-token" } } },
      { payload: { challengeId: `${passwordOnly.json().challengeId}\nsecret-mfa-login-challenge-control-token`, code: "000000" } },
      { payload: { challengeId: passwordOnly.json().challengeId, code: "000000\nsecret-mfa-login-code-control-token" } },
      { payload: { challengeId: passwordOnly.json().challengeId, code: "abcdefsecret-mfa-login-alpha-code-token" } },
      { payload: { challengeId: `${"m".repeat(161)}secret-mfa-login-long-challenge-token`, code: "000000" } },
      { payload: { challengeId: passwordOnly.json().challengeId, code: `${"1".repeat(33)}secret-mfa-login-long-code-token` } },
      { payload: ["secret-mfa-login-array-body-token"] },
      { headers: { "content-type": "application/json" }, payload: "null" }
    ];
    for (const requestOptions of malformedMfaLoginRequests) {
      const rejectedMalformed = await app.inject({
        method: "POST",
        url: "/api/login/mfa",
        headers: requestOptions.headers || {},
        payload: requestOptions.payload
      });
      assert.equal(rejectedMalformed.statusCode, 400, rejectedMalformed.body);
      assert.equal(rejectedMalformed.headers["set-cookie"], undefined);
      assert.doesNotMatch(rejectedMalformed.body, /secret-mfa-login-/);
    }
    assert.equal(challengeStatus(), beforeMalformedChallenge);
    assert.equal(failedMfaAuditCount(), beforeMalformedFailedAudits);
    assert.equal(verifiedSessionCount(), beforeMalformedVerifiedSessions);

    const rejectedChallenge = await app.inject({
      method: "POST",
      url: "/api/login/mfa",
      payload: { challengeId: passwordOnly.json().challengeId, code: "000000" }
    });
    assert.equal(rejectedChallenge.statusCode, 401);

    const completed = await app.inject({
      method: "POST",
      url: "/api/login/mfa",
      payload: { challengeId: passwordOnly.json().challengeId, code: totpCode(enrollment.setup.manualSetupKey) }
    });
    assert.equal(completed.statusCode, 200, completed.body);
    assert.equal(completed.json().ok, true);
    assert.equal(completed.json().mfaVerified, true);
    assert.ok(completed.headers["set-cookie"]);

    const suite = await app.inject({ method: "GET", url: "/api/suite", headers: { cookie: completed.headers["set-cookie"] } });
    assert.equal(suite.statusCode, 200, suite.body);
    assert.equal(suite.json().user.role, "Owner");

    const supportLogin = await app.inject({
      method: "POST",
      url: "/api/login",
      payload: { email: "support@armosphera.local", password: DEFAULT_PASSWORD }
    });
    assert.equal(supportLogin.statusCode, 200, supportLogin.body);
    assert.equal(supportLogin.json().mfaRequired, undefined);
    assert.ok(supportLogin.headers["set-cookie"]);

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: completed.headers["set-cookie"] },
      payload: { note: "MFA metadata is backed up without shared secrets." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    const factorBackup = backup.json().backup.payload.tables.user_mfa_factors.find(factor => factor.id === enrollment.factor.id);
    assert.equal(factorBackup.status, "active");
    assert.equal(factorBackup.secret_base32, undefined);
    assert.equal(factorBackup.secretExcluded, true);

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: completed.headers["set-cookie"] } });
    const auditTypes = audit.json().events.map(event => event.type);
    assert.ok(auditTypes.includes("security.mfa.enrolled"));
    assert.ok(auditTypes.includes("security.mfa.enabled"));
    assert.ok(auditTypes.includes("auth.mfa.challenge.created"));
    assert.ok(auditTypes.includes("auth.mfa.verified"));
  });
});

test("bearer logout revokes the bearer-authenticated session", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const token = /sid=([^;]+)/.exec(String(ownerCookie))?.[1];
    assert.ok(token, "login returns a sid token");

    const before = await app.inject({
      method: "GET",
      url: "/api/me",
      headers: { authorization: `Bearer ${token}` }
    });
    assert.equal(before.statusCode, 200, before.body);

    const logout = await app.inject({
      method: "POST",
      url: "/api/logout",
      headers: { authorization: `Bearer ${token}` }
    });
    assert.equal(logout.statusCode, 200, logout.body);

    const after = await app.inject({
      method: "GET",
      url: "/api/me",
      headers: { authorization: `Bearer ${token}` }
    });
    assert.equal(after.statusCode, 401);
  });
});

test("owner can inspect and revoke active sessions without exposing tokens", async () => {
  await withApp(async app => {
    const ownerLogin = await app.inject({
      method: "POST",
      url: "/api/login",
      headers: { "user-agent": "Owner desktop browser" },
      payload: { email: DEFAULT_EMAIL, password: DEFAULT_PASSWORD }
    });
    assert.equal(ownerLogin.statusCode, 200, ownerLogin.body);
    const ownerCookie = ownerLogin.headers["set-cookie"];

    const supportLogin = await app.inject({
      method: "POST",
      url: "/api/login",
      headers: { "user-agent": "Support mobile desk" },
      payload: { email: "support@armosphera.local", password: DEFAULT_PASSWORD }
    });
    assert.equal(supportLogin.statusCode, 200, supportLogin.body);
    const supportCookie = supportLogin.headers["set-cookie"];

    const supportDenied = await app.inject({
      method: "GET",
      url: "/api/admin/sessions",
      headers: { cookie: supportCookie }
    });
    assert.equal(supportDenied.statusCode, 403);

    const listed = await app.inject({
      method: "GET",
      url: "/api/admin/sessions",
      headers: { cookie: ownerCookie }
    });
    assert.equal(listed.statusCode, 200, listed.body);
    const body = listed.json();
    assert.equal(body.summary.activeSessions, 2);
    assert.equal(body.summary.privilegedActiveSessions, 1);
    assert.equal(body.summary.revokedSessions, 0);
    assert.ok(body.sessions.some(session => session.current === true && session.email === DEFAULT_EMAIL));
    const ownerSession = body.sessions.find(session => session.current === true);
    assert.ok(ownerSession.riskSignals.includes("privileged-session-without-mfa"));
    const supportSession = body.sessions.find(session => session.email === "support@armosphera.local");
    assert.equal(supportSession.status, "active");
    assert.equal(supportSession.userAgent, "Support mobile desk");
    assert.match(supportSession.sessionId, /^[a-f0-9]{24}$/);
    assert.equal(supportSession.token, undefined);
    assert.equal(JSON.stringify(body).includes(supportCookie.split("=")[1].slice(0, 16)), false);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: "/api/admin/sessions",
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    const auditorRevoke = await app.inject({
      method: "POST",
      url: `/api/admin/sessions/${supportSession.sessionId}/revoke`,
      headers: { cookie: auditorCookie },
      payload: { reason: "Auditor cannot revoke sessions" }
    });
    assert.equal(auditorRevoke.statusCode, 403);

    const revoked = await app.inject({
      method: "POST",
      url: `/api/admin/sessions/${supportSession.sessionId}/revoke`,
      headers: { cookie: ownerCookie },
      payload: { reason: "Support device lost during pilot" }
    });
    assert.equal(revoked.statusCode, 200, revoked.body);
    assert.equal(revoked.json().session.status, "revoked");
    assert.equal(revoked.json().session.revokedReason, "Support device lost during pilot");
    assert.equal(revoked.json().session.revokedByName, "Samvel Owner");

    const blockedSupport = await app.inject({
      method: "GET",
      url: "/api/suite",
      headers: { cookie: supportCookie }
    });
    assert.equal(blockedSupport.statusCode, 401);

    const ownerStillActive = await app.inject({
      method: "GET",
      url: "/api/suite",
      headers: { cookie: ownerCookie }
    });
    assert.equal(ownerStillActive.statusCode, 200, ownerStillActive.body);

    const after = await app.inject({
      method: "GET",
      url: "/api/admin/sessions",
      headers: { cookie: ownerCookie }
    });
    assert.equal(after.json().summary.activeSessions, 2);
    assert.equal(after.json().summary.revokedSessions, 1);
    assert.ok(after.json().sessions.some(session => session.sessionId === supportSession.sessionId && session.status === "revoked"));
    assert.equal(after.json().sessions.some(session => session.email === "support@armosphera.local" && session.status === "active"), false);

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "admin.session.revoked"
      && event.details.sessionId === supportSession.sessionId
      && event.details.targetUserId === "user-support"
    )));
  });
});

test("admin session revoke rejects malformed metadata before mutation", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const supportLogin = await app.inject({
      method: "POST",
      url: "/api/login",
      headers: { "user-agent": "Support tablet" },
      payload: { email: "support@armosphera.local", password: DEFAULT_PASSWORD }
    });
    assert.equal(supportLogin.statusCode, 200, supportLogin.body);
    const listed = await app.inject({
      method: "GET",
      url: "/api/admin/sessions",
      headers: { cookie: ownerCookie }
    });
    assert.equal(listed.statusCode, 200, listed.body);
    const supportSession = listed.json().sessions.find(session => session.email === "support@armosphera.local");
    assert.ok(supportSession);
    const revokeAuditCount = () => app.db.prepare(`
      SELECT COUNT(*) AS count
      FROM audit_events
      WHERE type = ?
    `).get("admin.session.revoked").count;
    const sessionRow = () => app.db.prepare(`
      SELECT revoked_at AS revokedAt, revoked_reason AS revokedReason
      FROM sessions
      WHERE user_id = ?
    `).get("user-support");
    const beforeAudit = revokeAuditCount();
    const malformedPayloads = [
      ["secret-session-revoke-array-body-token"],
      { reason: { text: "Device lost", token: "secret-session-revoke-object-reason-token" } },
      { reason: ["secret-session-revoke-array-reason-token"] },
      { reason: "Device lost\nsecret-session-revoke-control-reason-token" },
      { reason: `${"r".repeat(241)}secret-session-revoke-long-reason-token` }
    ];

    const rejectedNull = await app.inject({
      method: "POST",
      url: `/api/admin/sessions/${supportSession.sessionId}/revoke`,
      headers: { cookie: ownerCookie, "content-type": "application/json" },
      payload: "null"
    });
    assert.equal(rejectedNull.statusCode, 400, rejectedNull.body);
    assert.doesNotMatch(rejectedNull.body, /secret-session-revoke-/);
    assert.equal(sessionRow().revokedAt, null);
    assert.equal(revokeAuditCount(), beforeAudit);

    for (const payload of malformedPayloads) {
      const rejected = await app.inject({
        method: "POST",
        url: `/api/admin/sessions/${supportSession.sessionId}/revoke`,
        headers: { cookie: ownerCookie },
        payload
      });
      assert.equal(rejected.statusCode, 400, rejected.body);
      assert.doesNotMatch(rejected.body, /secret-session-revoke-/);
      assert.equal(sessionRow().revokedAt, null);
      assert.equal(revokeAuditCount(), beforeAudit);
    }

    const valid = await app.inject({
      method: "POST",
      url: `/api/admin/sessions/${supportSession.sessionId}/revoke`,
      headers: { cookie: ownerCookie },
      payload: {}
    });
    assert.equal(valid.statusCode, 200, valid.body);
    assert.equal(valid.json().session.revokedReason, "Administrative revocation");
    assert.equal(sessionRow().revokedReason, "Administrative revocation");
    assert.equal(revokeAuditCount(), beforeAudit + 1);
  });
});

test("owner can create tamper-evident audit export packet for auditor review", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const supportCookie = await login(app, "support@armosphera.local");

    const supportDenied = await app.inject({
      method: "GET",
      url: "/api/admin/audit-exports",
      headers: { cookie: supportCookie }
    });
    assert.equal(supportDenied.statusCode, 403);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorBefore = await app.inject({
      method: "GET",
      url: "/api/admin/audit-exports",
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorBefore.statusCode, 200, auditorBefore.body);
    assert.deepEqual(auditorBefore.json().exports, []);

    const auditorCreate = await app.inject({
      method: "POST",
      url: "/api/admin/audit-exports",
      headers: { cookie: auditorCookie },
      payload: { note: "Auditor should not create export packets" }
    });
    assert.equal(auditorCreate.statusCode, 403);

    const created = await app.inject({
      method: "POST",
      url: "/api/admin/audit-exports",
      headers: { cookie: ownerCookie },
      payload: {
        note: "Pilot audit packet for identity and access controls."
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const packet = created.json().export;
    assert.equal(packet.status, "verified");
    assert.match(packet.id, /^audit-export-/);
    assert.ok(packet.eventCount >= 4);
    assert.equal(packet.payload.kind, "armosphera-one-audit-export");
    assert.equal(packet.payload.organization.id, "org-armosphera-demo");
    assert.equal(packet.payload.events.length, packet.eventCount);
    assert.equal(packet.payload.chain.length, packet.eventCount);
    assert.equal(packet.payload.chainHead, packet.chainHead);
    assert.equal(packet.payload.events[0].id, packet.firstEventId);
    assert.equal(packet.payload.events.at(-1).id, packet.lastEventId);
    assert.equal(sha256(JSON.stringify(packet.payload)), packet.checksum);
    assert.equal(JSON.stringify(packet.payload).includes(ownerCookie.split("=")[1].slice(0, 16)), false);

    let previousHash = "GENESIS";
    for (const [index, event] of packet.payload.events.entries()) {
      const chainItem = packet.payload.chain[index];
      assert.equal(chainItem.eventId, event.id);
      assert.equal(chainItem.previousHash, previousHash);
      const expectedHash = sha256(JSON.stringify({ previousHash, event }));
      assert.equal(chainItem.eventHash, expectedHash);
      previousHash = expectedHash;
    }
    assert.equal(packet.chainHead, previousHash);
    assert.ok(packet.payload.events.some(event => event.type === "auth.login"));
    assert.ok(packet.payload.controls.includes("sha256-forward-hash-chain"));
    assert.ok(packet.payload.controls.includes("auditor-readable-owner-admin-writable"));

    const auditorDetail = await app.inject({
      method: "GET",
      url: `/api/admin/audit-exports/${packet.id}`,
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorDetail.statusCode, 200, auditorDetail.body);
    assert.equal(auditorDetail.json().export.id, packet.id);
    assert.equal(auditorDetail.json().export.payload.chainHead, packet.chainHead);

    const listed = await app.inject({
      method: "GET",
      url: "/api/admin/audit-exports",
      headers: { cookie: auditorCookie }
    });
    assert.equal(listed.statusCode, 200, listed.body);
    assert.ok(listed.json().exports.some(item => item.id === packet.id && item.payload === undefined));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: ownerCookie },
      payload: { note: "Audit export packet must be in tenant backup scope." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.audit_export_packets.some(item => item.id === packet.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "admin.audit_export.created"
      && event.details.exportId === packet.id
      && event.details.chainHead === packet.chainHead
    )));
  });
});

test("admin evidence packets reject malformed metadata before persistence", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const packetCounts = () => ({
      auditExports: app.db.prepare("SELECT COUNT(*) AS count FROM audit_export_packets WHERE org_id = ?").get("org-armosphera-demo").count,
      accessReviews: app.db.prepare("SELECT COUNT(*) AS count FROM access_review_packets WHERE org_id = ?").get("org-armosphera-demo").count,
      backups: app.db.prepare("SELECT COUNT(*) AS count FROM tenant_backup_packets WHERE org_id = ?").get("org-armosphera-demo").count,
      suiteEvents: app.db.prepare(`
        SELECT COUNT(*) AS count
        FROM suite_events
        WHERE org_id = ?
          AND event_type = ?
      `).get("org-armosphera-demo", "admin.access_review.created").count,
      auditEvents: app.db.prepare(`
        SELECT COUNT(*) AS count
        FROM audit_events
        WHERE org_id = ?
          AND type IN (?, ?, ?)
      `).get("org-armosphera-demo", "admin.audit_export.created", "admin.access_review.created", "admin.backup.created").count
    });
    const before = packetCounts();
    const targets = [
      "/api/admin/audit-exports",
      "/api/admin/access-reviews",
      "/api/admin/backups"
    ];
    const rejectedNull = async url => {
      const response = await app.inject({
        method: "POST",
        url,
        headers: { cookie, "content-type": "application/json" },
        payload: "null"
      });
      assert.equal(response.statusCode, 400, response.body);
      assert.doesNotMatch(response.body, /secret-admin-evidence-/);
    };
    const rejected = async (url, payload) => {
      const response = await app.inject({
        method: "POST",
        url,
        headers: { cookie },
        payload
      });
      assert.equal(response.statusCode, 400, response.body);
      assert.doesNotMatch(response.body, /secret-admin-evidence-/);
    };

    for (const url of targets) {
      await rejectedNull(url);
      await rejected(url, ["secret-admin-evidence-array-body-token"]);
      await rejected(url, { note: { value: "Ready", token: "secret-admin-evidence-object-note-token" } });
      await rejected(url, { note: "Ready\nsecret-admin-evidence-control-note-token" });
      await rejected(url, { note: `${"N".repeat(501)}secret-admin-evidence-long-note-token` });
    }
    await rejected("/api/admin/audit-exports", { periodStart: { value: "2026-06-01", token: "secret-admin-evidence-object-start-token" } });
    await rejected("/api/admin/audit-exports", { periodStart: "2026-02-30" });
    await rejected("/api/admin/audit-exports", { periodStart: "2026-06-01\nsecret-admin-evidence-control-start-token" });
    await rejected("/api/admin/audit-exports", { periodEnd: ["2026-06-30"] });
    await rejected("/api/admin/audit-exports", { periodStart: "2026-06-30", periodEnd: "2026-06-01" });
    await rejected("/api/admin/access-reviews", { reviewPeriod: { value: "2026-Q2", token: "secret-admin-evidence-object-period-token" } });
    await rejected("/api/admin/access-reviews", { reviewPeriod: "2026-Q9" });
    await rejected("/api/admin/access-reviews", { reviewPeriod: "2026-13" });
    await rejected("/api/admin/access-reviews", { reviewPeriod: "2026-Q2\nsecret-admin-evidence-control-period-token" });

    assert.deepEqual(packetCounts(), before);

    const auditExport = await app.inject({
      method: "POST",
      url: "/api/admin/audit-exports",
      headers: { cookie },
      payload: {
        periodStart: "2026-01-01",
        periodEnd: "2027-12-31",
        note: "Owner-created audit export after malformed metadata rejection."
      }
    });
    assert.equal(auditExport.statusCode, 200, auditExport.body);
    assert.equal(auditExport.json().export.note, "Owner-created audit export after malformed metadata rejection.");

    const accessReview = await app.inject({
      method: "POST",
      url: "/api/admin/access-reviews",
      headers: { cookie },
      payload: {
        reviewPeriod: "2026-06",
        note: "Owner-created access review after malformed metadata rejection."
      }
    });
    assert.equal(accessReview.statusCode, 200, accessReview.body);
    assert.equal(accessReview.json().review.reviewPeriod, "2026-06");

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie },
      payload: { note: "Owner-created backup after malformed metadata rejection." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.equal(backup.json().backup.note, "Owner-created backup after malformed metadata rejection.");

    const after = packetCounts();
    assert.equal(after.auditExports, before.auditExports + 1);
    assert.equal(after.accessReviews, before.accessReviews + 1);
    assert.equal(after.backups, before.backups + 1);
    assert.equal(after.suiteEvents, before.suiteEvents + 1);
    assert.equal(after.auditEvents, before.auditEvents + 3);
  });
});

test("owner can configure integration connector contracts without rebuilding commodity apps", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const supportCookie = await login(app, "support@armosphera.local");

    const supportDenied = await app.inject({
      method: "GET",
      url: "/api/integrations/connectors",
      headers: { cookie: supportCookie }
    });
    assert.equal(supportDenied.statusCode, 403);

    const initial = await app.inject({
      method: "GET",
      url: "/api/integrations/connectors",
      headers: { cookie: ownerCookie }
    });
    assert.equal(initial.statusCode, 200, initial.body);
    const connectorKeys = initial.json().connectors.map(connector => connector.connectorKey);
    for (const key of ["gmail", "google-calendar", "google-drive", "whatsapp-business", "telegram-bot", "esignature", "hayhashvapah-finance", "migration-import"]) {
      assert.ok(connectorKeys.includes(key), key);
    }
    const whatsappDefinition = initial.json().connectors.find(connector => connector.connectorKey === "whatsapp-business");
    assert.equal(whatsappDefinition.status, "planned");
    assert.equal(whatsappDefinition.rebuildPolicy, "external-provider-boundary");
    assert.ok(whatsappDefinition.capabilities.includes("inbound-message-intake"));
    assert.ok(whatsappDefinition.requiredScopes.includes("messages.write"));

    const configured = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/whatsapp-business/configure",
      headers: { cookie: ownerCookie },
      payload: {
        status: "connected",
        environment: "sandbox",
        endpointUrl: "https://graph.facebook.com/v20.0",
        secret: "whsec-whatsapp-boundary",
        scopes: ["messages.read", "messages.write", "contacts.read"],
        ownerRole: "Operator",
        note: "Pilot WhatsApp Business sandbox connector"
      }
    });
    assert.equal(configured.statusCode, 200, configured.body);
    const whatsapp = configured.json().connector;
    assert.equal(whatsapp.connectorKey, "whatsapp-business");
    assert.equal(whatsapp.status, "connected");
    assert.equal(whatsapp.secretExcluded, true);
    assert.match(whatsapp.secretFingerprint, /^[a-f0-9]{12}$/);
    assert.equal(JSON.stringify(whatsapp).includes("whsec-whatsapp-boundary"), false);
    assert.deepEqual(whatsapp.scopes, ["messages.read", "messages.write", "contacts.read"]);

    const readyCheck = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/whatsapp-business/health-check",
      headers: { cookie: ownerCookie },
      payload: { sampleEvent: "inbound-message", note: "Validate sandbox scope readiness" }
    });
    assert.equal(readyCheck.statusCode, 200, readyCheck.body);
    assert.equal(readyCheck.json().check.status, "ready");
    assert.deepEqual(readyCheck.json().check.missingScopes, []);
    assert.ok(readyCheck.json().check.checks.some(item => item.key === "secret-boundary" && item.status === "passed"));

    const driveConfigured = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/google-drive/configure",
      headers: { cookie: ownerCookie },
      payload: {
        status: "connected",
        environment: "sandbox",
        endpointUrl: "https://www.googleapis.com/drive/v3",
        secret: "drive-refresh-token",
        scopes: ["drive.metadata.readonly"],
        ownerRole: "Admin"
      }
    });
    assert.equal(driveConfigured.statusCode, 200, driveConfigured.body);

    const blockedCheck = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/google-drive/health-check",
      headers: { cookie: ownerCookie },
      payload: { note: "Drive file write scope intentionally absent" }
    });
    assert.equal(blockedCheck.statusCode, 200, blockedCheck.body);
    assert.equal(blockedCheck.json().check.status, "blocked");
    assert.deepEqual(blockedCheck.json().check.missingScopes, ["drive.file"]);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: "/api/integrations/connectors",
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    assert.ok(auditorList.json().connectors.some(connector => connector.connectorKey === "whatsapp-business" && connector.status === "connected"));

    const auditorConfigure = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/telegram-bot/configure",
      headers: { cookie: auditorCookie },
      payload: { status: "connected", secret: "telegram-secret" }
    });
    assert.equal(auditorConfigure.statusCode, 403);

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: ownerCookie },
      payload: { note: "Connector contracts and checks are backup-scoped without secrets." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    const connectorBackup = backup.json().backup.payload.tables.integration_connectors.find(connector => connector.connector_key === "whatsapp-business");
    assert.equal(connectorBackup.secret_hash, undefined);
    assert.equal(connectorBackup.secretExcluded, true);
    assert.match(connectorBackup.secretFingerprint, /^[a-f0-9]{12}$/);
    assert.equal(JSON.stringify(backup.json().backup.payload).includes("whsec-whatsapp-boundary"), false);
    assert.ok(backup.json().backup.payload.tables.integration_connector_checks.some(check => check.connector_key === "google-drive" && check.status === "blocked"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => event.type === "integration.connector.configured" && event.details.connectorKey === "whatsapp-business"));
    assert.ok(audit.json().events.some(event => event.type === "integration.connector.health_checked" && event.details.connectorKey === "google-drive" && event.details.status === "blocked"));
  });
});

test("integration connector rejects malformed path keys before mutation", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const auditCountBefore = app.db.prepare("SELECT COUNT(*) AS count FROM audit_events WHERE type IN (?, ?)")
      .get("integration.connector.configured", "integration.connector.health_checked").count;

    const malformedConfigure = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/whatsapp-business%0Asecret-connector-key-token/configure",
      headers: { cookie },
      payload: {
        status: "connected",
        environment: "sandbox",
        endpointUrl: "https://graph.facebook.com/v20.0",
        secret: "whsec-malformed-key",
        scopes: ["messages.read", "messages.write"],
        ownerRole: "Admin"
      }
    });
    assert.equal(malformedConfigure.statusCode, 400, malformedConfigure.body);
    assert.match(malformedConfigure.body, /Invalid integration connector key/);
    assert.doesNotMatch(malformedConfigure.body, /secret-connector-key-token|whsec-malformed-key/);

    const malformedHealth = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/telegram-bot%0Asecret-connector-key-health-token/health-check",
      headers: { cookie },
      payload: { note: "Malformed key should not create health evidence." }
    });
    assert.equal(malformedHealth.statusCode, 400, malformedHealth.body);
    assert.match(malformedHealth.body, /Invalid integration connector key/);
    assert.doesNotMatch(malformedHealth.body, /secret-connector-key-health-token/);

    const unknownSafe = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/unknown-connector/configure",
      headers: { cookie },
      payload: { status: "connected" }
    });
    assert.equal(unknownSafe.statusCode, 404, unknownSafe.body);

    const auditCountAfter = app.db.prepare("SELECT COUNT(*) AS count FROM audit_events WHERE type IN (?, ?)")
      .get("integration.connector.configured", "integration.connector.health_checked").count;
    assert.equal(auditCountAfter, auditCountBefore);
  });
});

test("integration connector rejects unknown owner roles before mutation", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const configured = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/whatsapp-business/configure",
      headers: { cookie },
      payload: {
        status: "connected",
        environment: "sandbox",
        endpointUrl: "https://graph.facebook.com/v20.0",
        secret: "whsec-owner-role-valid",
        scopes: ["messages.read", "messages.write", "contacts.read"],
        ownerRole: "Admin",
        note: "Valid connector owner role before invalid-role rejection."
      }
    });
    assert.equal(configured.statusCode, 200, configured.body);
    assert.equal(configured.json().connector.ownerRole, "Admin");

    const auditCountBefore = app.db.prepare("SELECT COUNT(*) AS count FROM audit_events WHERE type = ?")
      .get("integration.connector.configured").count;
    const rejected = await app.inject({
      method: "POST",
      url: "/api/integrations/connectors/whatsapp-business/configure",
      headers: { cookie },
      payload: {
        status: "connected",
        environment: "production",
        endpointUrl: "https://graph.facebook.com/v21.0",
        secret: "whsec-owner-role-invalid",
        scopes: ["messages.read", "messages.write", "contacts.read"],
        ownerRole: "Ghost Role",
        note: "Invalid connector role must not become readiness ownership evidence."
      }
    });
    assert.equal(rejected.statusCode, 400, rejected.body);
    assert.match(rejected.body, /Unknown role/);

    const row = app.db.prepare(`
      SELECT owner_role, endpoint_url, secret_fingerprint, environment
      FROM integration_connectors
      WHERE connector_key = ?
    `).get("whatsapp-business");
    assert.equal(row.owner_role, "Admin");
    assert.equal(row.endpoint_url, "https://graph.facebook.com/v20.0");
    assert.equal(row.environment, "sandbox");
    assert.equal(row.secret_fingerprint, sha256("whsec-owner-role-valid").slice(0, 12));
    assert.equal(row.secret_fingerprint === sha256("whsec-owner-role-invalid").slice(0, 12), false);

    const listed = await app.inject({ method: "GET", url: "/api/integrations/connectors", headers: { cookie } });
    assert.equal(listed.statusCode, 200, listed.body);
    const connector = listed.json().connectors.find(item => item.connectorKey === "whatsapp-business");
    assert.equal(connector.ownerRole, "Admin");
    assert.equal(JSON.stringify(listed.json()).includes("Ghost Role"), false);

    const auditCountAfter = app.db.prepare("SELECT COUNT(*) AS count FROM audit_events WHERE type = ?")
      .get("integration.connector.configured").count;
    assert.equal(auditCountAfter, auditCountBefore);
  });
});

