test("assigned roles can resolve clinic launch remediation actions with evidence", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const operatorCookie = await login(app, "operator@armosphera.local");
    const accountantCookie = await login(app, "accountant@armosphera.local");
    const supportCookie = await login(app, "support@armosphera.local");

    const installed = await app.inject({
      method: "POST",
      url: "/api/pilots/templates/clinic-wellness/install",
      headers: { cookie: ownerCookie },
      payload: {
        customerId: "cust-nare",
        selectedPackageKeys: ["patient-retention", "booking-inbox", "receivables-handoff"],
        pilotCount: 5
      }
    });
    assert.equal(installed.statusCode, 200, installed.body);

    const briefResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/owner-briefs",
      headers: { cookie: ownerCookie },
      payload: {
        installId: installed.json().install.id,
        reportDate: "2026-05-27"
      }
    });
    assert.equal(briefResponse.statusCode, 200, briefResponse.body);

    const workbenchResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/operator-workbenches",
      headers: { cookie: operatorCookie },
      payload: { briefId: briefResponse.json().brief.id }
    });
    assert.equal(workbenchResponse.statusCode, 200, workbenchResponse.body);

    const reviewResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/accountant-reviews",
      headers: { cookie: accountantCookie },
      payload: { workbenchId: workbenchResponse.json().workbench.id }
    });
    assert.equal(reviewResponse.statusCode, 200, reviewResponse.body);

    const readinessResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-readiness",
      headers: { cookie: ownerCookie },
      payload: {
        accountantReviewId: reviewResponse.json().review.id,
        targetLaunchDate: "2026-06-03"
      }
    });
    assert.equal(readinessResponse.statusCode, 200, readinessResponse.body);

    const planResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-remediation-plans",
      headers: { cookie: ownerCookie },
      payload: {
        launchReadinessId: readinessResponse.json().packet.id,
        note: "Owner creates blocker remediation plan before paid pilot offer."
      }
    });
    assert.equal(planResponse.statusCode, 200, planResponse.body);
    const plan = planResponse.json().plan;
    const totalActionCount = plan.payload.summary.actionCount;

    const supportDenied = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/remediation-actions/resolve-accountant-review/resolve",
      headers: { cookie: supportCookie },
      payload: {
        planId: plan.id,
        evidenceType: "accountant-review-note",
        evidence: "Support cannot close accounting remediation actions."
      }
    });
    assert.equal(supportDenied.statusCode, 403);

    const operatorDenied = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/remediation-actions/resolve-accountant-review/resolve",
      headers: { cookie: operatorCookie },
      payload: {
        planId: plan.id,
        evidenceType: "accountant-review-note",
        evidence: "Operator should not close accountant VAT review."
      }
    });
    assert.equal(operatorDenied.statusCode, 403);

    const malformedActionKey = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/remediation-actions/resolve-accountant-review%0Asecret-clinic-action-key-token/resolve",
      headers: { cookie: accountantCookie },
      payload: {
        planId: plan.id,
        evidenceType: "accountant-review-note",
        evidence: "secret-clinic-action-evidence-token"
      }
    });
    assert.equal(malformedActionKey.statusCode, 400, malformedActionKey.body);
    assert.match(malformedActionKey.body, /Invalid clinic pilot action key/);
    assert.doesNotMatch(malformedActionKey.body, /secret-clinic-action-key-token|secret-clinic-action-evidence-token/);

    const unknownSafeActionKey = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/remediation-actions/safe-unknown-action/resolve",
      headers: { cookie: accountantCookie },
      payload: {
        planId: plan.id,
        evidenceType: "accountant-review-note",
        evidence: "Safe unknown action key should preserve 404 behavior."
      }
    });
    assert.equal(unknownSafeActionKey.statusCode, 404, unknownSafeActionKey.body);

    const accountantResolved = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/remediation-actions/resolve-accountant-review/resolve",
      headers: { cookie: accountantCookie },
      payload: {
        planId: plan.id,
        evidenceType: "accountant-review-note",
        evidence: "VAT source and period lock reviewed for pilot launch.",
        note: "Accountant cleared legal/accounting launch blocker."
      }
    });
    assert.equal(accountantResolved.statusCode, 200, accountantResolved.body);
    const accountantResolution = accountantResolved.json().resolution;
    assert.equal(accountantResolution.status, "resolved");
    assert.equal(accountantResolution.actionKey, "resolve-accountant-review");
    assert.equal(accountantResolution.ownerRole, "Accountant");
    assert.equal(accountantResolution.payload.kind, "armosphera-one-pilot-remediation-resolution");
    assert.equal(accountantResolution.payload.action.sourceGate, "accountant-review");
    assert.equal(accountantResolution.payload.evidence.type, "accountant-review-note");
    assert.equal(accountantResolution.payload.progress.resolvedActionCount, 1);
    assert.equal(accountantResolution.payload.progress.totalActionCount, totalActionCount);
    assert.equal(accountantResolution.payload.progress.remainingActionCount, totalActionCount - 1);
    assert.equal(accountantResolution.payload.progress.allResolved, false);
    assert.equal(sha256(JSON.stringify(accountantResolution.payload)), accountantResolution.checksum);

    const repeated = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/remediation-actions/resolve-accountant-review/resolve",
      headers: { cookie: accountantCookie },
      payload: {
        planId: plan.id,
        evidenceType: "accountant-review-note",
        evidence: "VAT source and period lock reviewed for pilot launch."
      }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().resolution.id, accountantResolution.id);
    assert.equal(repeated.json().idempotent, true);

    const operatorResolved = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/remediation-actions/close-overdue-receivable-risk/resolve",
      headers: { cookie: operatorCookie },
      payload: {
        planId: plan.id,
        evidenceType: "payment-promise",
        evidence: "Customer promised payment before pilot launch.",
        note: "Operator documented collection risk closure evidence."
      }
    });
    assert.equal(operatorResolved.statusCode, 200, operatorResolved.body);
    const operatorResolution = operatorResolved.json().resolution;
    assert.equal(operatorResolution.actionKey, "close-overdue-receivable-risk");
    assert.equal(operatorResolution.ownerRole, "Operator");
    assert.equal(operatorResolution.moneyAtRisk, 960000);
    assert.equal(operatorResolution.payload.progress.resolvedActionCount, 2);
    assert.equal(operatorResolution.payload.progress.remainingActionCount, totalActionCount - 2);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/remediation-resolutions?planId=${plan.id}`,
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    assert.equal(auditorList.json().resolutions.length, 2);
    assert.ok(auditorList.json().resolutions.some(item => (
      item.id === accountantResolution.id
      && item.payload === undefined
      && item.actionKey === "resolve-accountant-review"
    )));

    const malformedResolutionListUrls = [
      `/api/pilots/clinic-wellness/remediation-resolutions?planId=${plan.id}%0Asecret-clinic-pilot-list-control-token`,
      "/api/pilots/clinic-wellness/remediation-resolutions?planId=" + "p".repeat(161)
    ];
    for (const url of malformedResolutionListUrls) {
      const rejectedList = await app.inject({
        method: "GET",
        url,
        headers: { cookie: auditorCookie }
      });
      assert.equal(rejectedList.statusCode, 400, rejectedList.body);
      assert.doesNotMatch(rejectedList.body, /secret-clinic-pilot-list-/);
    }

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: ownerCookie },
      payload: { note: "Pilot remediation resolution evidence must be restore-scoped." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.pilot_remediation_action_resolutions.some(item => item.id === accountantResolution.id));
    assert.ok(backup.json().backup.payload.tables.pilot_remediation_action_resolutions.some(item => item.id === operatorResolution.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "pilot.remediation_action.resolved"
      && event.details.resolutionId === accountantResolution.id
      && event.details.planId === plan.id
      && event.details.actionKey === "resolve-accountant-review"
    )));
  });
});

test("owner can create clinic pilot launch clearance packet after remediation evidence", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const operatorCookie = await login(app, "operator@armosphera.local");
    const accountantCookie = await login(app, "accountant@armosphera.local");
    const supportCookie = await login(app, "support@armosphera.local");

    const installed = await app.inject({
      method: "POST",
      url: "/api/pilots/templates/clinic-wellness/install",
      headers: { cookie: ownerCookie },
      payload: {
        customerId: "cust-nare",
        selectedPackageKeys: ["patient-retention", "booking-inbox", "receivables-handoff"],
        pilotCount: 5
      }
    });
    assert.equal(installed.statusCode, 200, installed.body);

    const briefResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/owner-briefs",
      headers: { cookie: ownerCookie },
      payload: {
        installId: installed.json().install.id,
        reportDate: "2026-05-27"
      }
    });
    assert.equal(briefResponse.statusCode, 200, briefResponse.body);

    const workbenchResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/operator-workbenches",
      headers: { cookie: operatorCookie },
      payload: { briefId: briefResponse.json().brief.id }
    });
    assert.equal(workbenchResponse.statusCode, 200, workbenchResponse.body);

    const reviewResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/accountant-reviews",
      headers: { cookie: accountantCookie },
      payload: { workbenchId: workbenchResponse.json().workbench.id }
    });
    assert.equal(reviewResponse.statusCode, 200, reviewResponse.body);

    const readinessResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-readiness",
      headers: { cookie: ownerCookie },
      payload: {
        accountantReviewId: reviewResponse.json().review.id,
        targetLaunchDate: "2026-06-03"
      }
    });
    assert.equal(readinessResponse.statusCode, 200, readinessResponse.body);

    const planResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-remediation-plans",
      headers: { cookie: ownerCookie },
      payload: { launchReadinessId: readinessResponse.json().packet.id }
    });
    assert.equal(planResponse.statusCode, 200, planResponse.body);
    const plan = planResponse.json().plan;
    const totalActionCount = plan.payload.actions.length;

    const supportDenied = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-clearance",
      headers: { cookie: supportCookie },
      payload: { remediationPlanId: plan.id }
    });
    assert.equal(supportDenied.statusCode, 403);

    const blockedResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-clearance",
      headers: { cookie: ownerCookie },
      payload: {
        remediationPlanId: plan.id,
        note: "Owner checks whether launch blockers are cleared."
      }
    });
    assert.equal(blockedResponse.statusCode, 200, blockedResponse.body);
    const blockedPacket = blockedResponse.json().packet;
    assert.equal(blockedPacket.status, "blocked");
    assert.equal(blockedPacket.payload.kind, "armosphera-one-pilot-launch-clearance");
    assert.equal(blockedPacket.payload.goLiveAllowed, false);
    assert.equal(blockedPacket.payload.clearanceDecision, "blocked-remediation-open");
    assert.equal(blockedPacket.payload.summary.totalActionCount, totalActionCount);
    assert.equal(blockedPacket.payload.summary.resolvedActionCount, 0);
    assert.equal(blockedPacket.payload.summary.unresolvedActionCount, totalActionCount);
    assert.ok(blockedPacket.payload.unresolvedActions.some(action => action.key === "resolve-accountant-review"));
    assert.equal(sha256(JSON.stringify(blockedPacket.payload)), blockedPacket.checksum);

    for (const action of plan.payload.actions) {
      const actorCookie = action.ownerRole === "Accountant"
        ? accountantCookie
        : action.ownerRole === "Operator"
          ? operatorCookie
          : ownerCookie;
      const resolved = await app.inject({
        method: "POST",
        url: `/api/pilots/clinic-wellness/remediation-actions/${action.key}/resolve`,
        headers: { cookie: actorCookie },
        payload: {
          planId: plan.id,
          evidenceType: `${action.category || action.sourceGate}-clearance`,
          evidence: `${action.title} resolved for launch clearance.`,
          note: "Launch clearance proof."
        }
      });
      assert.equal(resolved.statusCode, 200, resolved.body);
    }

    const clearedResponse = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-clearance",
      headers: { cookie: ownerCookie },
      payload: {
        remediationPlanId: plan.id,
        note: "Owner confirms all remediation evidence before paid pilot offer."
      }
    });
    assert.equal(clearedResponse.statusCode, 200, clearedResponse.body);
    const packet = clearedResponse.json().packet;
    assert.equal(packet.status, "cleared");
    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.remediationPlanId, plan.id);
    assert.equal(packet.launchReadinessId, plan.launchReadinessId);
    assert.equal(packet.payload.kind, "armosphera-one-pilot-launch-clearance");
    assert.equal(packet.payload.customer.id, "cust-nare");
    assert.equal(packet.payload.goLiveAllowed, true);
    assert.equal(packet.payload.clearanceDecision, "ready-for-paid-pilot");
    assert.equal(packet.payload.summary.totalActionCount, totalActionCount);
    assert.equal(packet.payload.summary.resolvedActionCount, totalActionCount);
    assert.equal(packet.payload.summary.unresolvedActionCount, 0);
    assert.equal(packet.payload.summary.completionPercent, 100);
    assert.equal(packet.payload.resolvedActions.length, totalActionCount);
    assert.deepEqual(packet.payload.unresolvedActions, []);
    assert.ok(packet.payload.controls.includes("all-remediation-actions-resolved-with-checksums"));
    assert.ok(packet.payload.resolvedActions.every(action => /^[a-f0-9]{64}$/.test(action.resolutionChecksum)));
    assert.equal(sha256(JSON.stringify(packet.payload)), packet.checksum);

    const repeated = await app.inject({
      method: "POST",
      url: "/api/pilots/clinic-wellness/launch-clearance",
      headers: { cookie: ownerCookie },
      payload: { remediationPlanId: plan.id }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().packet.id, packet.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: "/api/pilots/clinic-wellness/launch-clearance",
      headers: { cookie: auditorCookie }
    });
    assert.equal(auditorList.statusCode, 200, auditorList.body);
    assert.ok(auditorList.json().packets.some(item => (
      item.id === packet.id
      && item.payload === undefined
      && item.status === "cleared"
      && item.resolvedActionCount === totalActionCount
    )));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: ownerCookie },
      payload: { note: "Pilot launch clearance evidence must be restore-scoped." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.pilot_launch_clearance_packets.some(item => item.id === packet.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "pilot.launch_clearance.created"
      && event.details.packetId === packet.id
      && event.details.remediationPlanId === plan.id
      && event.details.status === "cleared"
    )));
  });
});

