    assert.equal(packet.invoiceId, proof.invoice.id);
    assert.equal(packet.paymentId, proof.payment.id);
    assert.equal(packet.renewalTaskId, created.json().renewalTask.id);
    assert.equal(packet.invoiceNumber, "HHV-PILOT-2026-0001");
    assert.equal(packet.paymentReference, "ACBA-PILOT-2026-0001");
    assert.equal(packet.amount, 1704000);
    assert.equal(packet.periodKey, "2026-05");
    assert.equal(packet.renewalDueDate, "2026-06-10");
    assert.equal(packet.payload.kind, "armosphera-one-pilot-closeout-renewal-handoff");
    assert.equal(packet.payload.paymentCollection.id, proof.paymentCollectionPacket.id);
    assert.equal(packet.payload.paymentCollection.checksum, proof.paymentCollectionPacket.checksum);
    assert.equal(packet.payload.renewalTask.id, created.json().renewalTask.id);
    assert.equal(packet.payload.renewalTask.dueDate, "2026-06-10");
    assert.equal(packet.payload.renewalTask.sourceKey, `pilot-closeout-renewal:${proof.paymentCollectionPacket.id}`);
    assert.ok(packet.payload.controls.includes("paid-pilot-closeout-after-collection"));
    assert.ok(packet.payload.controls.includes("crm-renewal-task-created"));
    assert.equal(sha256(JSON.stringify(packet.payload)), packet.checksum);

    const repeated = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/payment-collections/${proof.paymentCollectionPacket.id}/closeout-packet`,
      headers: { cookie: proof.ownerCookie },
      payload: { renewalDueDate: "2026-06-10" }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().packet.id, packet.id);
    assert.equal(repeated.json().renewalTask.id, created.json().renewalTask.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/closeouts?paymentCollectionPacketId=${proof.paymentCollectionPacket.id}`,
      headers: { cookie: auditorCookie }
    });
