    const decision = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${proof.renewalQuoteApproval.id}/decision`,
      headers: { cookie: proof.ownerCookie },
      payload: { decision: "approved", note: "Owner approved clinic monthly renewal quote release." }
    });
