    assert.equal(packet.payload.draftInvoice.id, executedBody.draftInvoice.id);
    assert.equal(packet.payload.draftInvoice.status, "draft");
    assert.equal(packet.payload.draftInvoice.total, 960000);
    assert.equal(packet.payload.draftInvoice.subtotal, 800000);
