    assert.ok(backup.json().backup.payload.tables.pilot_next_renewal_hayhashvapah_invoice_posting_packets.some(item => item.id === packet.id));
    assert.ok(backup.json().backup.payload.tables.invoices.some(item => item.id === postedBody.invoice.id));
