    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.nextRenewalPaymentCollectionPacketId, proof.nextRenewalPaymentCollectionPacket.id);
    assert.equal(packet.nextRenewalPostingPacketId, proof.nextRenewalPostingPacket.id);
    assert.equal(packet.nextRenewalDraftPacketId, proof.nextRenewalDraftPacket.id);
    assert.equal(packet.nextRenewalAcceptanceHandoffId, proof.nextRenewalAcceptanceHandoff.id);
    assert.equal(packet.nextRenewalQuoteReleasePacketId, proof.nextRenewalQuoteReleasePacket.id);
    assert.equal(packet.nextRenewalQuoteHandoffId, proof.nextRenewalQuoteHandoff.id);
    assert.equal(packet.renewalCloseoutPacketId, proof.renewalCloseoutPacket.id);
    assert.equal(packet.renewalPaymentCollectionPacketId, proof.renewalPaymentCollectionPacket.id);
    assert.equal(packet.renewalPostingPacketId, proof.renewalPostingPacket.id);
    assert.equal(packet.renewalDraftPacketId, proof.renewalDraftPacket.id);
    assert.equal(packet.renewalAcceptanceHandoffId, proof.renewalAcceptanceHandoff.id);
