    assert.equal(packet.renewalQuoteHandoffId, proof.renewalQuoteHandoff.id);
    assert.equal(packet.closeoutPacketId, proof.closeoutPacket.id);
    assert.equal(packet.priorPaymentCollectionPacketId, proof.paymentCollectionPacket.id);
