    assert.equal(packet.paymentId, proof.nextRenewalPayment.id);
    assert.equal(packet.invoiceNumber, "HHV-NEXT-RENEWAL-2026-0001");
    assert.equal(packet.paymentReference, "ACBA-NEXT-RENEWAL-2026-0001");
    assert.equal(packet.amount, 960000);
    assert.equal(packet.periodKey, "2026-06");
    assert.equal(packet.closeoutDate, "2026-06-29");
    assert.equal(packet.followingRenewalDueDate, "2026-07-29");
    assert.equal(packet.payload.kind, "armosphera-one-pilot-next-renewal-cycle-closeout");
