      event.type === "pilot.following_renewal_hayhashvapah_invoice_posting.created"
      && event.details.packetId === packet.id
      && event.details.followingRenewalDraftPacketId === proof.followingRenewalDraftPacket.id
      && event.details.invoiceId === postedBody.invoice.id
      && event.details.invoiceLinkId === postedBody.link.id
