    assert.equal(packet.subsequentRenewalDueDate, "2026-08-29");
    assert.equal(packet.payload.kind, "armosphera-one-pilot-following-renewal-closeout");
    assert.equal(packet.payload.followingRenewalPaymentCollection.id, proof.followingRenewalPaymentCollectionPacket.id);
    assert.equal(packet.payload.followingRenewalPaymentCollection.checksum, proof.followingRenewalPaymentCollectionPacket.checksum);
    assert.equal(packet.payload.followingRenewalPostingPacket.id, proof.followingRenewalPostingPacket.id);
    assert.equal(packet.payload.followingRenewalDraftPacket.id, proof.followingRenewalDraftPacket.id);
    assert.equal(packet.payload.followingRenewalAcceptanceHandoff.id, proof.followingRenewalAcceptanceHandoff.id);
