    assert.equal(packet.nextRenewalQuoteHandoffId, proof.nextRenewalQuoteHandoff.id);
    assert.equal(packet.renewalCloseoutPacketId, proof.renewalCloseoutPacket.id);
    assert.equal(packet.renewalPaymentCollectionPacketId, proof.renewalPaymentCollectionPacket.id);
    assert.equal(packet.renewalPostingPacketId, proof.renewalPostingPacket.id);
    assert.equal(packet.renewalDraftPacketId, proof.renewalDraftPacket.id);
    assert.equal(packet.renewalAcceptanceHandoffId, proof.renewalAcceptanceHandoff.id);
    assert.equal(packet.renewalQuoteReleasePacketId, proof.renewalQuoteReleasePacket.id);
    assert.equal(packet.renewalQuoteHandoffId, proof.renewalQuoteHandoff.id);
    assert.equal(packet.closeoutPacketId, proof.closeoutPacket.id);
    assert.equal(packet.priorPaymentCollectionPacketId, proof.paymentCollectionPacket.id);
    assert.equal(packet.priorPostingPacketId, proof.postingPacket.id);
    assert.equal(packet.renewalTaskId, proof.renewalTask.id);
    assert.equal(packet.nextRenewalTaskId, proof.nextRenewalTask.id);
