    assert.equal(created.statusCode, 200, created.body);
    const body = created.json();
    const handoff = body.handoff;
    assert.equal(handoff.status, "ongoing-renewal-quote-release-pending");
    assert.equal(handoff.templateKey, "clinic-wellness");
    assert.equal(handoff.continuationRenewalCloseoutPacketId, proof.continuationRenewalCloseoutPacket.id);
    assert.equal(handoff.continuationRenewalPaymentCollectionPacketId, proof.continuationRenewalPaymentCollectionPacket.id);
