    assert.equal(handoff.continuationRenewalQuoteReleasePacketId, proof.continuationRenewalQuoteReleasePacket.id);
    assert.equal(handoff.continuationRenewalQuoteHandoffId, proof.continuationRenewalQuoteHandoff.id);
    assert.equal(handoff.subsequentRenewalCloseoutPacketId, proof.subsequentRenewalCloseoutPacket.id);
