    assert.equal(handoff.subsequentRenewalPostingPacketId, proof.subsequentRenewalPostingPacket.id);
    assert.equal(handoff.subsequentRenewalDraftPacketId, proof.subsequentRenewalDraftPacket.id);
    assert.equal(handoff.subsequentRenewalAcceptanceHandoffId, proof.subsequentRenewalAcceptanceHandoff.id);
    assert.equal(handoff.subsequentRenewalQuoteReleasePacketId, proof.subsequentRenewalQuoteReleasePacket.id);
    assert.equal(handoff.subsequentRenewalQuoteHandoffId, proof.subsequentRenewalQuoteHandoff.id);
