    assert.equal(packet.payload.payment.reference, "ACBA-NEXT-ONGOING-RENEWAL-2026-0001");
    assert.ok(packet.payload.controls.includes("next-ongoing-renewal-payment-confirmed-before-closeout"));
    assert.ok(packet.payload.controls.includes("next-ongoing-renewal-payment-collection-checksum-linked"));
    assert.ok(packet.payload.controls.includes("next-ongoing-renewal-official-posting-checksum-linked"));
    assert.ok(packet.payload.controls.includes("crm-following-ongoing-renewal-task-created"));
    assert.ok(packet.payload.controls.includes("ready-for-following-ongoing-renewal-quote-cycle"));
    assert.equal(sha256(JSON.stringify(packet.payload)), packet.checksum);

    const repeated = await app.inject({
      method: "POST",
      url: `/api/pilots/clinic-wellness/next-ongoing-renewal-payment-collections/${proof.nextOngoingRenewalPaymentCollectionPacket.id}/closeout-packet`,
      headers: { cookie: proof.ownerCookie },
      payload: { followingOngoingRenewalDueDate: "2026-12-29" }
    });
