    assert.equal(repeated.json().packet.id, packet.id);
    assert.equal(repeated.json().followingOngoingRenewalTask.id, followingOngoingRenewalTask.id);
    assert.equal(repeated.json().idempotent, true);

    const auditorCookie = await login(app, "auditor@armosphera.local");
    const auditorList = await app.inject({
      method: "GET",
      url: `/api/pilots/clinic-wellness/next-ongoing-renewal-closeouts?paymentCollectionPacketId=${proof.nextOngoingRenewalPaymentCollectionPacket.id}`,
      headers: { cookie: auditorCookie }
    });
