    assert.equal(created.statusCode, 200, created.body);
    const packet = created.json().packet;
    assert.equal(packet.status, "subsequent-ongoing-renewal-draft-created");
    assert.equal(packet.templateKey, "clinic-wellness");
    assert.equal(packet.subsequentOngoingRenewalAcceptanceHandoffId, proof.subsequentOngoingRenewalAcceptanceHandoff.id);
    assert.equal(packet.subsequentOngoingRenewalQuoteReleasePacketId, proof.subsequentOngoingRenewalQuoteReleasePacket.id);
    assert.equal(packet.subsequentOngoingRenewalQuoteHandoffId, proof.subsequentOngoingRenewalQuoteHandoff.id);
    assert.equal(packet.followingOngoingRenewalCloseoutPacketId, proof.followingOngoingRenewalCloseoutPacket.id);
    assert.equal(packet.followingOngoingRenewalPaymentCollectionPacketId, proof.followingOngoingRenewalPaymentCollectionPacket.id);
    assert.equal(packet.followingOngoingRenewalPostingPacketId, proof.followingOngoingRenewalPostingPacket.id);
    assert.equal(packet.followingOngoingRenewalDraftPacketId, proof.followingOngoingRenewalDraftPacket.id);
    assert.equal(packet.followingOngoingRenewalAcceptanceHandoffId, proof.followingOngoingRenewalAcceptanceHandoff.id);
