    assert.equal(packet.followingOngoingRenewalQuoteHandoffId, proof.followingOngoingRenewalQuoteHandoff.id);
    assert.equal(packet.nextOngoingRenewalCloseoutPacketId, proof.nextOngoingRenewalCloseoutPacket.id);
