    assert.equal(packet.payload.subsequentOngoingRenewalAcceptanceHandoff.id, proof.subsequentOngoingRenewalAcceptanceHandoff.id);
    assert.equal(packet.payload.subsequentOngoingRenewalAcceptanceHandoff.checksum, proof.subsequentOngoingRenewalAcceptanceHandoff.checksum);
    assert.equal(packet.payload.release.id, proof.subsequentOngoingRenewalQuoteReleasePacket.id);
    assert.equal(packet.payload.release.checksum, proof.subsequentOngoingRenewalQuoteReleasePacket.checksum);
    assert.equal(packet.payload.handoff.id, proof.subsequentOngoingRenewalQuoteHandoff.id);
    assert.equal(packet.payload.handoff.checksum, proof.subsequentOngoingRenewalQuoteHandoff.checksum);
    assert.equal(packet.payload.followingOngoingRenewalCloseout.id, proof.followingOngoingRenewalCloseoutPacket.id);
    assert.equal(packet.payload.followingOngoingRenewalCloseout.checksum, proof.followingOngoingRenewalCloseoutPacket.checksum);
