    assert.ok(packet.payload.controls.includes("subsequent-ongoing-monthly-renewal-invoice-ready-for-official-posting"));
    assert.ok(packet.payload.controls.includes("subsequent-ongoing-renewal-acceptance-handoff-checksum-linked"));
