test("approved legal answer workflow publishes cited guidance once", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const created = await app.inject({
      method: "POST",
      url: "/api/legal/questions",
      headers: { cookie },
      payload: {
        customerId: "cust-nare",
        topic: "vat",
        question: "Can the approved VAT answer be published to the customer service timeline?"
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const approvalId = created.json().approval.id;
    const answerId = created.json().answer.id;
    const questionId = created.json().question.id;

    const decision = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${approvalId}/decision`,
      headers: { cookie },
      payload: { decision: "approved", note: "Accountant approved for publication" }
    });
    assert.equal(decision.statusCode, 200, decision.body);

    const executed = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${approvalId}/execute`,
      headers: { cookie }
    });
    assert.equal(executed.statusCode, 200, executed.body);
    const body = executed.json();
    assert.equal(body.idempotent, false);
    assert.equal(body.run.resultType, "legal_publication");
    assert.equal(body.publication.answerId, answerId);
    assert.equal(body.publication.questionId, questionId);
    assert.equal(body.publication.status, "published");
    assert.ok(body.publication.sourceIds.includes("law-tax-code"));
    assert.equal(body.approval.status, "executed");
    assert.ok(body.events.some(event => event.eventType === "legal.answer.published"));
    assert.ok(body.events.some(event => event.eventType === "workflow.action.executed"));

    const repeated = await app.inject({
      method: "POST",
      url: `/api/workflow/approvals/${approvalId}/execute`,
      headers: { cookie }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().idempotent, true);
    assert.equal(repeated.json().publication.id, body.publication.id);

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie } });
    const customer = customer360.json();
    const legalQuestion = customer.legalQuestions.find(question => question.id === questionId);
    assert.equal(legalQuestion.status, "published");
    assert.equal(legalQuestion.answer.publication.id, body.publication.id);
    assert.ok(customer.workflowRuns.some(run => run.id === body.run.id && run.resultType === "legal_publication"));
    assert.ok(customer.timeline.some(event => event.eventType === "legal.answer.published"));

    const runs = await app.inject({ method: "GET", url: "/api/workflow/runs?customerId=cust-nare", headers: { cookie } });
    assert.ok(runs.json().runs.some(run => run.id === body.run.id && run.resultId === body.publication.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.ok(audit.json().events.some(event => event.type === "legal.answer.published" && event.details.answerId === answerId));
    assert.ok(audit.json().events.some(event => event.type === "workflow.action.executed" && event.details.runId === body.run.id));
  });
});

