    assert.equal(body.summary.campaignCount, 1);
    assert.equal(body.summary.totalSpend, 250000);
    assert.equal(body.summary.influencedPipeline, 720000);
    assert.equal(body.summary.paidRevenue, 420000);
    assert.equal(body.summary.roiPercent, 68);
    assert.equal(body.definitions.paidRevenue, "Paid invoices and payment receipts from attributed customers");

    const campaign = body.campaigns.find(item => item.id === "camp-armenia-growth-pilot");
