    assert.equal(campaign.channel, "Instagram/WhatsApp");
    assert.equal(campaign.leadCount, 1);
    assert.equal(campaign.customerCount, 1);
    assert.equal(campaign.dealCount, 1);
    assert.equal(campaign.spend, 250000);
    assert.equal(campaign.influencedPipeline, 720000);
    assert.equal(campaign.paidRevenue, 420000);
    assert.equal(campaign.roiPercent, 68);
    assert.ok(campaign.attributions.some(item => item.customerId === "cust-van" && item.dealId === "deal-van-season"));
