test("workflow approval decision rejects malformed metadata before persistence", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const approvalStatus = () => app.db.prepare(`
      SELECT status, decided_by_user_id AS decidedByUserId, decided_at AS decidedAt
      FROM workflow_approvals
      WHERE id = ?
    `).get("approval-overdue-nare");
    const suiteApprovalEventCount = () => app.db.prepare(`
      SELECT COUNT(*) AS count
      FROM suite_events
      WHERE event_type IN ('workflow.approval.approved', 'workflow.approval.rejected')
    `).get().count;
    const auditApprovalEventCount = () => app.db.prepare(`
      SELECT COUNT(*) AS count
      FROM audit_events
      WHERE type IN ('workflow.approval.approved', 'workflow.approval.rejected')
    `).get().count;

    const beforeApproval = approvalStatus();
    assert.equal(beforeApproval.status, "pending");
    assert.equal(beforeApproval.decidedByUserId, null);
    assert.equal(beforeApproval.decidedAt, null);
    const suiteEventCountBefore = suiteApprovalEventCount();
    const auditCountBefore = auditApprovalEventCount();
    const malformedRequests = [
      {
        decision: ["approved"],
        note: "Array decisions must not be coerced into approval.",
        token: "secret-workflow-approval-array-decision-token"
      },
      {
        decision: { value: "approved", token: "secret-workflow-approval-object-decision-token" },
        note: "Object decisions must not become approval evidence."
      },
      {
        decision: "approved",
        note: { text: "Object notes must not become evidence.", token: "secret-workflow-approval-object-note-token" }
      },
      {
        decision: "approved",
        note: "Approval note\nwith control character.",
        token: "secret-workflow-approval-control-note-token"
      },
      {
        decision: "approved",
        note: `${"A".repeat(501)}secret-workflow-approval-long-note-token`
      },
      ["approved"],
      null
    ];

    for (const payload of malformedRequests) {
      const rejected = await app.inject({
        method: "POST",
        url: "/api/workflow/approvals/approval-overdue-nare/decision",
        headers: { cookie },
        payload
      });
      assert.equal(rejected.statusCode, 400, rejected.body);
      assert.doesNotMatch(rejected.body, /secret-workflow-approval-/);
    }

    const afterRejectedApprovals = approvalStatus();
    assert.equal(afterRejectedApprovals.status, "pending");
    assert.equal(afterRejectedApprovals.decidedByUserId, null);
    assert.equal(afterRejectedApprovals.decidedAt, null);
    assert.equal(suiteApprovalEventCount(), suiteEventCountBefore);
    assert.equal(auditApprovalEventCount(), auditCountBefore);

    const decision = await app.inject({
      method: "POST",
      url: "/api/workflow/approvals/approval-overdue-nare/decision",
      headers: { cookie },
      payload: { decision: "approved", note: "Owner approved after malformed decision checks" }
    });
    assert.equal(decision.statusCode, 200, decision.body);
    assert.equal(decision.json().approval.status, "approved");
    assert.ok(decision.json().events.some(event => (
      event.eventType === "workflow.approval.approved"
      && event.payload.note === "Owner approved after malformed decision checks"
    )));
  });
});

test("approved service reply workflow sends knowledge-grounded response once", async () => {
  await withApp(async app => {
    const cookie = await login(app);

    const blocked = await app.inject({
      method: "POST",
      url: "/api/workflow/approvals/approval-vat-reply-nare/execute",
      headers: { cookie }
    });
    assert.equal(blocked.statusCode, 409);

    const decision = await app.inject({
      method: "POST",
      url: "/api/workflow/approvals/approval-vat-reply-nare/decision",
      headers: { cookie },
      payload: { decision: "approved", note: "Owner approved VAT wording for WhatsApp response" }
    });
    assert.equal(decision.statusCode, 200, decision.body);

    const executed = await app.inject({
      method: "POST",
      url: "/api/workflow/approvals/approval-vat-reply-nare/execute",
      headers: { cookie }
    });
    assert.equal(executed.statusCode, 200, executed.body);
    const body = executed.json();
    assert.equal(body.idempotent, false);
    assert.equal(body.run.resultType, "service_reply");
    assert.equal(body.case.id, "case-nare-vat");
    assert.equal(body.case.status, "waiting-customer");
    assert.equal(body.case.slaStatus, "waiting-customer");
    assert.equal(body.reply.authorType, "operator");
    assert.equal(body.reply.approvalState, "human-approved");
    assert.match(body.reply.body, /VAT invoice wording for Armenian procurement/);
    assert.match(body.reply.body, /HayHashvapah invoice/);
    assert.equal(body.approval.status, "executed");
    assert.ok(body.events.some(event => event.eventType === "service.reply.sent"));
    assert.ok(body.events.some(event => event.eventType === "workflow.action.executed"));

    const repeated = await app.inject({
      method: "POST",
      url: "/api/workflow/approvals/approval-vat-reply-nare/execute",
      headers: { cookie }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().idempotent, true);
    assert.equal(repeated.json().reply.id, body.reply.id);

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie } });
    const customer = customer360.json();
    assert.ok(customer.service.cases.some(serviceCase => serviceCase.id === "case-nare-vat" && serviceCase.messageCount === 3));
    assert.ok(customer.workflowRuns.some(run => run.id === body.run.id && run.resultType === "service_reply"));
    assert.ok(customer.timeline.some(event => event.eventType === "service.reply.sent"));

    const consoleResponse = await app.inject({ method: "GET", url: "/api/service/console", headers: { cookie } });
    assert.equal(consoleResponse.statusCode, 200, consoleResponse.body);
    assert.ok(!consoleResponse.json().approvals.some(approval => approval.id === "approval-vat-reply-nare"));
    assert.ok(consoleResponse.json().runs.some(run => run.id === body.run.id && run.resultType === "service_reply"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.ok(audit.json().events.some(event => event.type === "service.reply.sent" && event.details.caseId === "case-nare-vat"));
    assert.ok(audit.json().events.some(event => event.type === "workflow.action.executed" && event.details.runId === body.run.id));
  });
});

test("support can generate grounded advisory ticket summary with knowledge recommendation without external actions", async () => {
  await withApp(async app => {
    const supportCookie = await login(app, "support@armosphera.local");
    const accountantCookie = await login(app, "accountant@armosphera.local");
    const ownerCookie = await login(app);

    const before360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie: ownerCookie } });
    assert.equal(before360.statusCode, 200, before360.body);
    const beforeCustomer = before360.json();
    const beforeCase = beforeCustomer.service.cases.find(serviceCase => serviceCase.id === "case-nare-vat");
    assert.equal(beforeCase.status, "open");
    const workflowRunCountBefore = beforeCustomer.workflowRuns.length;
    const messageCountBefore = beforeCase.messageCount;
    const approvalCountBefore = beforeCustomer.approvals.length;

    const denied = await app.inject({
      method: "POST",
      url: "/api/ai/ticket-summaries",
      headers: { cookie: accountantCookie },
      payload: { caseId: "case-nare-vat", prompt: "Summarize support risk" }
    });
    assert.equal(denied.statusCode, 403);

    const created = await app.inject({
      method: "POST",
      url: "/api/ai/ticket-summaries",
      headers: { cookie: supportCookie },
      payload: {
        caseId: "case-nare-vat",
        prompt: "Summarize the ticket and recommend the best reviewed knowledge article."
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const body = created.json();
    assert.equal(body.summary.caseId, "case-nare-vat");
    assert.equal(body.summary.caseNumber, "AO-CASE-1001");
    assert.equal(body.summary.customerId, "cust-nare");
    assert.equal(body.summary.status, "generated");
    assert.equal(body.summary.advisoryOnly, true);
    assert.equal(body.summary.reviewRequired, true);
    assert.equal(body.summary.modelPolicy, "deterministic-grounded-ticket-summary");
    assert.equal(body.summary.recommendedKnowledgeArticleId, "KB-AM-VAT-INVOICE-WORDING");
    assert.equal(body.summary.recommendedKnowledgeReview, "accountant-review-required");
    assert.ok(body.summary.confidence >= 80);
    assert.ok(body.summary.summary.includes("AO-CASE-1001"));
    assert.ok(body.summary.summary.includes("Նարե Բժշկական Կենտրոն"));
    assert.ok(body.summary.recommendedNextActions.some(action => /human-approved|review/i.test(action)));
    assert.ok(body.summary.groundingSources.some(source => source.type === "service_case"));
    assert.ok(body.summary.groundingSources.some(source => source.type === "case_message"));
    assert.ok(body.summary.groundingSources.some(source => source.type === "knowledge_article"));
    assert.ok(body.summary.groundingSources.some(source => source.type === "customer_profile"));
    assert.match(body.summary.checksum, /^[a-f0-9]{64}$/);
    assert.ok(body.events.some(event => event.eventType === "ai.ticket_summary.generated"));

    const listed = await app.inject({
      method: "GET",
      url: "/api/ai/ticket-summaries?caseId=case-nare-vat",
      headers: { cookie: supportCookie }
    });
    assert.equal(listed.statusCode, 200, listed.body);
    assert.ok(listed.json().summaries.some(summary => summary.id === body.summary.id && summary.checksum === body.summary.checksum));

    const consoleResponse = await app.inject({ method: "GET", url: "/api/service/console", headers: { cookie: supportCookie } });
    assert.equal(consoleResponse.statusCode, 200, consoleResponse.body);
    assert.ok(consoleResponse.json().ticketSummaries.some(summary => summary.id === body.summary.id));

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie: ownerCookie } });
    const customer = customer360.json();
    const afterCase = customer.service.cases.find(serviceCase => serviceCase.id === "case-nare-vat");
    assert.equal(afterCase.status, "open");
    assert.equal(afterCase.messageCount, messageCountBefore);
    assert.equal(customer.workflowRuns.length, workflowRunCountBefore);
    assert.equal(customer.approvals.length, approvalCountBefore);
    assert.ok(customer.ai.ticketSummaries.some(summary => summary.id === body.summary.id));
    assert.ok(customer.timeline.some(event => event.eventType === "ai.ticket_summary.generated"));

    const backup = await app.inject({
      method: "POST",
      url: "/api/admin/backups",
      headers: { cookie: ownerCookie },
      payload: { note: "Ticket summary evidence is included in tenant backup scope." }
    });
    assert.equal(backup.statusCode, 200, backup.body);
    assert.ok(backup.json().backup.payload.tables.ai_ticket_summaries.some(summary => summary.id === body.summary.id));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "ai.ticket_summary.generated"
      && event.details.summaryId === body.summary.id
      && event.details.caseId === "case-nare-vat"
      && event.details.advisoryOnly === true
    )));
  });
});

test("service manager escalates an at-risk case into supervisor queue once", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const managerCookie = await login(app, "service.manager@armosphera.local");
    const supportCookie = await login(app, "support@armosphera.local");

    const rejected = await app.inject({
      method: "POST",
      url: "/api/service/cases/case-nare-vat/escalate",
      headers: { cookie: supportCookie },
      payload: {
        severity: "sla-risk",
        reason: "Front-line support cannot trigger supervisor escalation evidence"
      }
    });
    assert.equal(rejected.statusCode, 403);

    const escalated = await app.inject({
      method: "POST",
      url: "/api/service/cases/case-nare-vat/escalate",
      headers: { cookie: managerCookie },
      payload: {
        severity: "sla-risk",
        reason: "VAT procurement answer is at risk and needs supervisor ownership before SLA breach"
      }
    });
    assert.equal(escalated.statusCode, 200, escalated.body);
    const body = escalated.json();
    assert.equal(body.idempotent, false);
    assert.equal(body.escalation.caseId, "case-nare-vat");
    assert.equal(body.escalation.customerId, "cust-nare");
    assert.equal(body.escalation.severity, "sla-risk");
    assert.equal(body.escalation.status, "open");
    assert.equal(body.escalation.escalatedByName, "Service Manager");
    assert.equal(body.escalation.assignedToName, "Service Manager");
    assert.match(body.escalation.reason, /supervisor ownership/);
    assert.equal(body.case.status, "escalated");
    assert.equal(body.case.slaStatus, "escalated");
    assert.equal(body.case.ownerName, "Service Manager");
    assert.equal(body.messages.at(-1).authorType, "supervisor");
    assert.ok(body.events.some(event => event.eventType === "service.case.escalated"));

    const duplicate = await app.inject({
      method: "POST",
      url: "/api/service/cases/case-nare-vat/escalate",
      headers: { cookie: managerCookie },
      payload: {
        severity: "customer-risk",
        reason: "Do not create duplicate open escalations"
      }
    });
    assert.equal(duplicate.statusCode, 200, duplicate.body);
    assert.equal(duplicate.json().idempotent, true);
    assert.equal(duplicate.json().escalation.id, body.escalation.id);

    const consoleResponse = await app.inject({ method: "GET", url: "/api/service/console", headers: { cookie: managerCookie } });
    assert.equal(consoleResponse.statusCode, 200, consoleResponse.body);
    assert.equal(consoleResponse.json().queue.escalatedOpen, 1);
    assert.ok(consoleResponse.json().escalations.some(item => item.id === body.escalation.id));
    assert.ok(consoleResponse.json().cases.some(serviceCase => serviceCase.id === "case-nare-vat" && serviceCase.slaStatus === "escalated"));

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie: managerCookie } });
    const customer = customer360.json();
    assert.equal(customer.service.openEscalations, 1);
    assert.ok(customer.service.escalations.some(item => item.id === body.escalation.id && item.status === "open"));
    assert.ok(customer.timeline.some(event => event.eventType === "service.case.escalated"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => event.type === "service.case.escalated" && event.details.escalationId === body.escalation.id));
  });
});

