test("workflow test-event validates trigger payload without mutating records", async () => {
  await withApp(async app => {
    const ownerCookie = await login(app);
    const serviceManagerCookie = await login(app, "service.manager@armosphera.local");

    const before360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie: ownerCookie } });
    assert.equal(before360.statusCode, 200, before360.body);
    const taskCountBefore = before360.json().crm.tasks.length;

    const created = await app.inject({
      method: "POST",
      url: "/api/workflow/rules/rule-overdue-task/test-event",
      headers: { cookie: serviceManagerCookie },
      payload: {
        eventType: "invoice_overdue",
        customerId: "cust-nare",
        subjectType: "invoice",
        subjectId: "inv-1007",
        payload: {
          invoiceNumber: "HHV-1007",
          overdueDays: 6,
          source: "HayHashvapah test event"
        },
        note: "Validate overdue invoice trigger before enabling live customer collection automation."
      }
    });
    assert.equal(created.statusCode, 200, created.body);
    const body = created.json();
    assert.equal(body.testEvent.ruleId, "rule-overdue-task");
    assert.equal(body.testEvent.eventType, "invoice_overdue");
    assert.equal(body.testEvent.customerId, "cust-nare");
    assert.equal(body.testEvent.subjectType, "invoice");
    assert.equal(body.testEvent.subjectId, "inv-1007");
    assert.equal(body.testEvent.status, "matched");
    assert.equal(body.testEvent.actionKey, "crm.task.create");
    assert.equal(body.testEvent.evaluation.proposedTask.invoiceNumber, "HHV-1007");
    assert.equal(body.testEvent.evaluation.noRecordsCreated, true);
    assert.ok(body.testEvent.guardrails.includes("test-event-only-no-records-created"));
    assert.ok(body.testEvent.guardrails.includes("human-approval-required-before-execution"));
    assert.match(body.testEvent.checksum, /^[a-f0-9]{64}$/);
    assert.ok(body.events.some(event => event.eventType === "workflow.test_event.created"));

    const testEvents = await app.inject({ method: "GET", url: "/api/workflow/test-events?customerId=cust-nare", headers: { cookie: ownerCookie } });
    assert.equal(testEvents.statusCode, 200, testEvents.body);
    assert.ok(testEvents.json().testEvents.some(event => event.id === body.testEvent.id && event.checksum === body.testEvent.checksum));

    const rules = await app.inject({ method: "GET", url: "/api/workflow/rules", headers: { cookie: ownerCookie } });
    assert.ok(rules.json().rules.some(rule => (
      rule.id === "rule-overdue-task"
      && rule.lastTestEvent?.id === body.testEvent.id
      && rule.lastTestEvent.status === "matched"
    )));

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie: ownerCookie } });
    const customer = customer360.json();
    assert.equal(customer.crm.tasks.length, taskCountBefore);
    assert.ok(customer.workflowTestEvents.some(event => event.id === body.testEvent.id));
    assert.ok(customer.timeline.some(event => event.eventType === "workflow.test_event.created"));

    const disabled = await app.inject({
      method: "POST",
      url: "/api/workflow/rules/rule-overdue-task/state",
      headers: { cookie: ownerCookie },
      payload: {
        enabled: false,
        reason: "Pause collection automation while testing event payload governance."
      }
    });
    assert.equal(disabled.statusCode, 200, disabled.body);

    const blocked = await app.inject({
      method: "POST",
      url: "/api/workflow/rules/rule-overdue-task/test-event",
      headers: { cookie: serviceManagerCookie },
      payload: {
        eventType: "invoice_overdue",
        customerId: "cust-nare",
        subjectType: "invoice",
        subjectId: "inv-1007"
      }
    });
    assert.equal(blocked.statusCode, 409);

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie: ownerCookie } });
    assert.ok(audit.json().events.some(event => (
      event.type === "workflow.test_event.created"
      && event.details.testEventId === body.testEvent.id
      && event.details.ruleId === "rule-overdue-task"
      && event.details.subjectId === "inv-1007"
    )));
  });
});

