    const sent = await app.inject({
      method: "POST",
      url: `/api/crm/collection-promises/${promise.id}/send-reminder`,
      headers: { cookie },
      payload: { provider: "WhatsApp Business Sandbox" }
    });
    assert.equal(sent.statusCode, 200, sent.body);
    const body = sent.json();
    assert.equal(body.idempotent, false);
    assert.equal(body.delivery.promiseId, promise.id);
    assert.equal(body.delivery.invoiceNumber, "HHV-1007");
    assert.equal(body.delivery.channel, "WhatsApp");
    assert.equal(body.delivery.provider, "WhatsApp Business Sandbox");
