test("owner can create idempotent SRC export packet from posted HayHashvapah invoices", async () => {
  await withApp(async app => {
    const cookie = await login(app);
    const accountantCookie = await login(app, "accountant@armosphera.local");
    await reviewVatSource(app, accountantCookie);
    const draft = await executeDraftInvoice(app, cookie);
    const posted = await app.inject({
      method: "POST",
      url: `/api/finance/draft-invoices/${draft.id}/post`,
      headers: { cookie },
      payload: { number: "HHV-SRC-2026-0002" }
    });
    assert.equal(posted.statusCode, 200, posted.body);
    const invoice = posted.json().invoice;

    const created = await app.inject({
      method: "POST",
      url: "/api/finance/src-exports",
      headers: { cookie },
      payload: { periodKey: "2026-05", note: "Prepare May VAT export packet for accountant review" }
    });
    assert.equal(created.statusCode, 200, created.body);
    const body = created.json();
    assert.equal(body.idempotent, false);
    assert.equal(body.export.periodKey, "2026-05");
    assert.equal(body.export.status, "prepared");
    assert.equal(body.export.legalSourceId, "law-tax-code");
    assert.equal(body.export.invoiceCount, 1);
    assert.equal(body.export.total, invoice.total);
    assert.equal(body.export.vat, invoice.vat);
    assert.match(body.export.checksum, /^[a-f0-9]{64}$/);
    assert.equal(body.export.payload.organization.taxId, "01234567");
    assert.equal(body.export.payload.legalSource.status, "active");
    assert.equal(body.export.payload.legalSource.latestReviewRole, "Accountant");
    assert.equal(body.export.payload.invoices[0].number, "HHV-SRC-2026-0002");
    assert.equal(body.export.payload.invoices[0].customer.taxId, "02576111");
    assert.ok(body.events.some(event => event.eventType === "finance.src_export.created"));

    const repeated = await app.inject({
      method: "POST",
      url: "/api/finance/src-exports",
      headers: { cookie },
      payload: { periodKey: "2026-05", note: "Duplicate May export request" }
    });
    assert.equal(repeated.statusCode, 200, repeated.body);
    assert.equal(repeated.json().idempotent, true);
    assert.equal(repeated.json().export.id, body.export.id);
    assert.equal(repeated.json().export.checksum, body.export.checksum);

    const listed = await app.inject({ method: "GET", url: "/api/finance/src-exports?periodKey=2026-05", headers: { cookie } });
    assert.equal(listed.statusCode, 200, listed.body);
    assert.ok(listed.json().exports.some(item => item.id === body.export.id));

    for (const url of ["/api/finance/src-exports", "/api/finance/src-exports?periodKey="]) {
      const unfilteredList = await app.inject({ method: "GET", url, headers: { cookie } });
      assert.equal(unfilteredList.statusCode, 200, unfilteredList.body);
      assert.ok(unfilteredList.json().exports.some(item => item.id === body.export.id));
    }

    for (const url of [
      "/api/finance/src-exports?periodKey=2026-13",
      "/api/finance/src-exports?periodKey=2026-00",
      "/api/finance/src-exports?periodKey=2026/05",
      "/api/finance/src-exports?periodKey=2026-05&periodKey=2026-06"
    ]) {
      const malformedList = await app.inject({ method: "GET", url, headers: { cookie } });
      assert.equal(malformedList.statusCode, 400, malformedList.body);
    }

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.ok(audit.json().events.some(event => event.type === "finance.src_export.created" && event.details.exportId === body.export.id));
  });
});

