test("closed finance period records failed workflow run and retries after reopening", async () => {
  await withApp(async app => {
    const cookie = await login(app);

    const closed = await app.inject({
      method: "POST",
      url: "/api/finance/periods/2026-05/close",
      headers: { cookie },
      payload: { reason: "Monthly VAT reporting submitted" }
    });
    assert.equal(closed.statusCode, 200, closed.body);
    assert.equal(closed.json().period.status, "closed");

    const decision = await app.inject({
      method: "POST",
      url: "/api/workflow/approvals/approval-deal-nare-invoice/decision",
      headers: { cookie },
      payload: { decision: "approved", note: "Attempt after close" }
    });
    assert.equal(decision.statusCode, 200, decision.body);

    const blocked = await app.inject({
      method: "POST",
      url: "/api/workflow/approvals/approval-deal-nare-invoice/execute",
      headers: { cookie }
    });
    assert.equal(blocked.statusCode, 409);
    assert.match(blocked.body, /PERIOD_LOCKED/);
    const blockedBody = blocked.json();
    assert.equal(blockedBody.run.status, "failed");
    assert.equal(blockedBody.run.resultType, "workflow_guardrail");
    assert.equal(blockedBody.run.payload.errorCode, "PERIOD_LOCKED");
    assert.equal(blockedBody.run.payload.retryable, true);
    assert.equal(blockedBody.run.payload.attempts.length, 1);
    assert.ok(blockedBody.events.some(event => event.eventType === "workflow.action.failed"));

    const drafts = await app.inject({ method: "GET", url: "/api/finance/draft-invoices", headers: { cookie } });
    assert.equal(drafts.statusCode, 200, drafts.body);
    assert.deepEqual(drafts.json().draftInvoices, []);

    const runs = await app.inject({ method: "GET", url: "/api/workflow/runs?customerId=cust-nare", headers: { cookie } });
    assert.equal(runs.statusCode, 200, runs.body);
    const failedRun = runs.json().runs.find(run => run.approvalId === "approval-deal-nare-invoice");
    assert.equal(failedRun.status, "failed");
    assert.equal(failedRun.payload.nextRetryAction, "Reopen finance period 2026-05 before retrying HayHashvapah draft invoice workflow.");

    const reopened = await app.inject({
      method: "POST",
      url: "/api/finance/periods/2026-05/reopen",
      headers: { cookie }
    });
    assert.equal(reopened.statusCode, 200, reopened.body);

    const retried = await app.inject({
      method: "POST",
      url: `/api/workflow/runs/${failedRun.id}/retry`,
      headers: { cookie }
    });
    assert.equal(retried.statusCode, 200, retried.body);
    const retriedBody = retried.json();
    assert.equal(retriedBody.run.id, failedRun.id);
    assert.equal(retriedBody.run.status, "completed");
    assert.equal(retriedBody.run.resultType, "finance_draft_invoice");
    assert.equal(retriedBody.run.payload.retryOf, failedRun.id);
    assert.equal(retriedBody.run.payload.previousFailure.errorCode, "PERIOD_LOCKED");
    assert.equal(retriedBody.run.payload.attempts.length, 2);
    assert.equal(retriedBody.draftInvoice.periodKey, "2026-05");
    assert.equal(retriedBody.approval.status, "executed");
    assert.ok(retriedBody.events.some(event => event.eventType === "workflow.action.retried"));
    assert.ok(retriedBody.events.some(event => event.eventType === "workflow.action.executed"));

    const customer360 = await app.inject({ method: "GET", url: "/api/customer-360/cust-nare", headers: { cookie } });
    assert.ok(customer360.json().workflowRuns.some(run => run.id === failedRun.id && run.status === "completed"));

    const audit = await app.inject({ method: "GET", url: "/api/audit", headers: { cookie } });
    assert.ok(audit.json().events.some(event => event.type === "workflow.action.failed" && event.details.runId === failedRun.id));
    assert.ok(audit.json().events.some(event => event.type === "workflow.action.retried" && event.details.runId === failedRun.id));
  });
});

